import React, { useState, useRef } from 'react';
import { User as UserIcon, Lock, Key, Music, ArrowRight, LogIn, Download, Upload, Settings, AlertTriangle, Check, X } from 'lucide-react';
import { User } from '../types';
import { STORAGE_KEY, STORAGE_KEY_USERS } from '../constants';

interface AuthViewProps {
  onLogin: (user: User) => void;
  usersDb: User[];
  onRegister: (newUser: User) => void;
}

export const AuthView: React.FC<AuthViewProps> = ({ onLogin, usersDb, onRegister }) => {
  const [isRegistering, setIsRegistering] = useState(false);
  const [showDataModal, setShowDataModal] = useState(false);

  // Form States
  const [appUsername, setAppUsername] = useState('');
  const [password, setPassword] = useState('');
  const [lastFmUsername, setLastFmUsername] = useState('');
  const [lastFmApiKey, setLastFmApiKey] = useState('');

  const [error, setError] = useState<string | null>(null);
  const [successMsg, setSuccessMsg] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    if (!appUsername || !password) {
      setError('Username and Password are required.');
      return;
    }

    if (isRegistering) {
      // REGISTER LOGIC
      if (usersDb.some(u => u.appUsername.toLowerCase() === appUsername.toLowerCase())) {
        setError('Username already taken.');
        return;
      }

      const newUser: User = {
        id: Date.now().toString(),
        appUsername,
        password,
        lastFmUsername: lastFmUsername || '', 
        lastFmApiKey: lastFmApiKey || '',
        lastCheckInDate: null
      };

      onRegister(newUser);
    } else {
      // LOGIN LOGIC
      const foundUser = usersDb.find(
        u => u.appUsername.toLowerCase() === appUsername.toLowerCase() && u.password === password
      );

      if (foundUser) {
        onLogin(foundUser);
      } else {
        setError('Invalid username or password.');
      }
    }
  };

  // --- DATA MANAGEMENT LOGIC ---

  const handleExportData = () => {
    try {
      const usersData = localStorage.getItem(STORAGE_KEY_USERS);
      const playlistData = localStorage.getItem(STORAGE_KEY);

      const backupData = {
        version: 1,
        timestamp: new Date().toISOString(),
        users: usersData ? JSON.parse(usersData) : [],
        playlist: playlistData ? JSON.parse(playlistData) : [],
      };

      const blob = new Blob([JSON.stringify(backupData, null, 2)], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `streamguard_backup_${new Date().toISOString().slice(0, 10)}.json`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);

      setSuccessMsg('Backup downloaded successfully!');
      setTimeout(() => setSuccessMsg(null), 3000);
    } catch (err) {
      setError('Failed to generate backup.');
    }
  };

  const handleImportClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);

        // Simple validation
        if (!json.users && !json.playlist) {
            throw new Error('Invalid backup file format');
        }

        if (window.confirm('This will overwrite current data. Are you sure?')) {
            if (json.users) {
                localStorage.setItem(STORAGE_KEY_USERS, JSON.stringify(json.users));
            }
            if (json.playlist) {
                localStorage.setItem(STORAGE_KEY, JSON.stringify(json.playlist));
            }
            alert('Data restored! The page will now reload.');
            window.location.reload();
        }
      } catch (err) {
        setError('Invalid backup file. Could not restore.');
      }
    };
    reader.readAsText(file);
    // Reset input
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="w-full max-w-md mx-auto p-4 animate-fade-in relative">
      <div className="mb-8 text-center">
        <div className="mx-auto w-20 h-20 bg-gradient-to-br from-neon-purple to-blue-600 rounded-full flex items-center justify-center mb-4 shadow-[0_0_30px_rgba(176,38,255,0.4)]">
          <Music size={40} className="text-white" />
        </div>
        <h1 className="text-4xl font-extrabold tracking-tight text-transparent bg-clip-text bg-gradient-to-r from-neon-green to-blue-400 mb-2">
          StreamGuard
        </h1>
        <p className="text-purple-200 opacity-80 font-medium">
          {isRegistering ? 'Create your Community Profile' : 'Welcome Back, Streamer'}
        </p>
      </div>

      <div className="glass p-8 rounded-3xl shadow-[0_0_40px_rgba(0,0,0,0.5)] border border-white/10 relative">

        {/* Settings/Data Button */}
        <button 
            onClick={() => setShowDataModal(true)}
            className="absolute top-4 right-4 text-gray-500 hover:text-white transition-colors p-2"
            title="Data Management"
        >
            <Settings size={20} />
        </button>

        <form onSubmit={handleSubmit} className="space-y-4">

          {/* App Login Credentials */}
          <div className="space-y-4">
            <div>
              <label className="block text-xs font-bold text-gray-400 mb-1 uppercase tracking-wider">Username</label>
              <div className="relative">
                <UserIcon className="absolute left-3 top-3.5 text-gray-500" size={18} />
                <input 
                  type="text" 
                  value={appUsername}
                  onChange={(e) => setAppUsername(e.target.value)}
                  className="w-full bg-black/40 border border-white/10 rounded-xl pl-10 pr-4 py-3 focus:outline-none focus:border-neon-purple text-white placeholder-gray-600 transition-colors"
                  placeholder="Create a login username"
                />
              </div>
            </div>
            <div>
              <label className="block text-xs font-bold text-gray-400 mb-1 uppercase tracking-wider">Password</label>
              <div className="relative">
                <Lock className="absolute left-3 top-3.5 text-gray-500" size={18} />
                <input 
                  type="password" 
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="w-full bg-black/40 border border-white/10 rounded-xl pl-10 pr-4 py-3 focus:outline-none focus:border-neon-purple text-white placeholder-gray-600 transition-colors"
                  placeholder="********"
                />
              </div>
            </div>
          </div>

          {/* Extended Fields for Registration */}
          {isRegistering && (
            <div className="pt-4 border-t border-white/10 space-y-4 animate-fade-in">
              <p className="text-xs text-neon-green font-mono text-center mb-2">LAST.FM CONFIGURATION</p>
              <div>
                <label className="block text-xs font-bold text-gray-400 mb-1 uppercase tracking-wider">Last.fm Username</label>
                <div className="relative">
                  <UserIcon className="absolute left-3 top-3.5 text-gray-500" size={18} />
                  <input 
                    type="text" 
                    value={lastFmUsername}
                    onChange={(e) => setLastFmUsername(e.target.value)}
                    className="w-full bg-black/40 border border-white/10 rounded-xl pl-10 pr-4 py-3 focus:outline-none focus:border-neon-green text-white placeholder-gray-600 transition-colors"
                    placeholder="Your Last.fm ID"
                  />
                </div>
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-400 mb-1 uppercase tracking-wider">Last.fm API Key</label>
                <div className="relative">
                  <Key className="absolute left-3 top-3.5 text-gray-500" size={18} />
                  <input 
                    type="password" 
                    value={lastFmApiKey}
                    onChange={(e) => setLastFmApiKey(e.target.value)}
                    className="w-full bg-black/40 border border-white/10 rounded-xl pl-10 pr-4 py-3 focus:outline-none focus:border-neon-green text-white placeholder-gray-600 transition-colors"
                    placeholder="32-character API Key"
                  />
                </div>
                <p className="text-[10px] text-gray-500 mt-1 pl-1">
                  We save this securely in your browser so you don't type it again.
                </p>
              </div>
            </div>
          )}

          {error && (
            <div className="text-red-400 text-sm text-center bg-red-900/20 p-2 rounded-lg border border-red-500/20 flex items-center justify-center gap-2">
              <AlertTriangle size={16} /> {error}
            </div>
          )}

          <button 
            type="submit"
            className="w-full py-4 rounded-xl font-bold flex items-center justify-center gap-2 transition-all mt-4 bg-gradient-to-r from-neon-purple to-pink-600 text-white shadow-[0_0_20px_rgba(176,38,255,0.4)] hover:scale-[1.02]"
          >
            {isRegistering ? (
              <>Create Account <ArrowRight size={20} /></>
            ) : (
              <>Login to Stream <LogIn size={20} /></>
            )}
          </button>
        </form>

        <div className="mt-6 text-center">
          <button 
            onClick={() => {
              setIsRegistering(!isRegistering);
              setError(null);
            }}
            className="text-gray-400 hover:text-white text-sm transition-colors hover:underline"
          >
            {isRegistering ? 'Already have an account? Login' : "Don't have an account? Register"}
          </button>
        </div>
      </div>

      {/* Data Management Modal */}
      {showDataModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/90 backdrop-blur-md p-4 animate-fade-in">
             <div className="glass max-w-sm w-full p-6 rounded-3xl relative border border-white/10 shadow-[0_0_50px_rgba(0,0,0,0.5)]">
                <button 
                    onClick={() => {
                        setShowDataModal(false);
                        setSuccessMsg(null);
                        setError(null);
                    }}
                    className="absolute top-4 right-4 text-gray-400 hover:text-white"
                >
                    <X size={20} />
                </button>

                <h3 className="text-xl font-bold mb-4 flex items-center gap-2">
                    <Settings className="text-neon-purple" /> Data Backup
                </h3>
                <p className="text-sm text-gray-400 mb-6">
                    Because this app runs in your browser without a server, use this to move your data to another device.
                </p>

                <div className="space-y-3">
                    <button 
                        onClick={handleExportData}
                        className="w-full py-3 bg-white/5 border border-white/10 hover:bg-white/10 rounded-xl flex items-center justify-center gap-2 transition-all"
                    >
                        <Download size={18} className="text-neon-green" /> Backup My Data
                    </button>

                    <div className="relative">
                        <input 
                            type="file" 
                            ref={fileInputRef}
                            onChange={handleFileChange}
                            accept=".json"
                            className="hidden"
                        />
                        <button 
                            onClick={handleImportClick}
                            className="w-full py-3 bg-white/5 border border-white/10 hover:bg-white/10 rounded-xl flex items-center justify-center gap-2 transition-all"
                        >
                            <Upload size={18} className="text-blue-400" /> Restore Backup
                        </button>
                    </div>
                </div>

                {successMsg && (
                    <div className="mt-4 text-green-400 text-sm text-center bg-green-900/20 p-2 rounded-lg flex items-center justify-center gap-2">
                        <Check size={16} /> {successMsg}
                    </div>
                )}
             </div>
        </div>
      )}
    </div>
  );
};

import { User, TargetTrack } from '../types';
import { STORAGE_KEY, STORAGE_KEY_USERS, DEFAULT_TRACKS } from '../constants';

// --- DATA SERVICE LAYER ---
// Currently uses LocalStorage, but designed to be easily swapped 
// with a real MySQL/Supabase API call in the future.

// Helper to simulate network delay (optional, for realism)
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const storageService = {

  // --- USER METHODS ---

  async getUsers(): Promise<User[]> {
    // MySQL Example: return fetch('/api/users').then(res => res.json());
    const stored = localStorage.getItem(STORAGE_KEY_USERS);
    return stored ? JSON.parse(stored) : [];
  },

  async registerUser(newUser: User): Promise<User> {
    // MySQL Example: return fetch('/api/register', { method: 'POST', body: ... });
    const users = await this.getUsers();
    if (users.some(u => u.appUsername.toLowerCase() === newUser.appUsername.toLowerCase())) {
      throw new Error('Username already taken');
    }
    const updatedUsers = [...users, newUser];
    localStorage.setItem(STORAGE_KEY_USERS, JSON.stringify(updatedUsers));
    return newUser;
  },

  async loginUser(username: string, password: string): Promise<User> {
    // MySQL Example: return fetch('/api/login', { method: 'POST', body: ... });
    const users = await this.getUsers();
    const user = users.find(u => 
      u.appUsername.toLowerCase() === username.toLowerCase() && 
      u.password === password
    );
    if (!user) throw new Error('Invalid credentials');
    return user;
  },

  async updateUserCheckIn(userId: string, dateString: string): Promise<User> {
    // MySQL Example: return fetch(`/api/users/${userId}/checkin`, { method: 'POST' ... });
    const users = await this.getUsers();
    let updatedUser: User | null = null;

    const newUsers = users.map(u => {
      if (u.id === userId) {
        updatedUser = { ...u, lastCheckInDate: dateString };
        return updatedUser;
      }
      return u;
    });

    if (!updatedUser) throw new Error('User not found');

    localStorage.setItem(STORAGE_KEY_USERS, JSON.stringify(newUsers));
    return updatedUser!;
  },

  // --- TRACK METHODS ---

  async getTracks(): Promise<TargetTrack[]> {
    // MySQL Example: return fetch('/api/tracks').then(res => res.json());
    const stored = localStorage.getItem(STORAGE_KEY);
    return stored ? JSON.parse(stored) : DEFAULT_TRACKS;
  },

  async saveTracks(tracks: TargetTrack[]): Promise<void> {
    // MySQL Example: return fetch('/api/tracks', { method: 'POST', body: ... });
    localStorage.setItem(STORAGE_KEY, JSON.stringify(tracks));
  },

  // --- BACKUP UTILS (Frontend Only) ---

  exportData() {
    return {
      users: localStorage.getItem(STORAGE_KEY_USERS),
      tracks: localStorage.getItem(STORAGE_KEY)
    };
  },

  importData(usersJson: string | null, tracksJson: string | null) {
    if (usersJson) localStorage.setItem(STORAGE_KEY_USERS, usersJson);
    if (tracksJson) localStorage.setItem(STORAGE_KEY, tracksJson);
  }
};

import React, { useState, useEffect } from 'react';
import { Lock, Unlock, X } from 'lucide-react';
import { ViewMode, TargetTrack, User } from './types';
import { ADMIN_PIN } from './constants';
import { AdminPanel } from './components/AdminPanel';
import { MemberView } from './components/MemberView';
import { AuthView } from './components/AuthView';
import { storageService } from './services/storage';

function App() {
  const [viewMode, setViewMode] = useState<ViewMode>(ViewMode.AUTH);
  const [targetTracks, setTargetTracks] = useState<TargetTrack[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  // Pin Modal State
  const [isPinModalOpen, setIsPinModalOpen] = useState(false);
  const [pinInput, setPinInput] = useState('');
  const [pinError, setPinError] = useState(false);

  // Initialize Data
  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    try {
      const tracks = await storageService.getTracks();
      setTargetTracks(tracks);
    } catch (e) {
      console.error("Failed to load data", e);
    }
  };

  // Save tracks handler
  const handleSaveTracks = async (newTracks: TargetTrack[]) => {
    await storageService.saveTracks(newTracks);
    setTargetTracks(newTracks);
    alert('Playlist updated successfully!');
  };

  // Auth Handlers
  const handleRegister = async (newUser: User) => {
    try {
      // In a real DB app, you'd send data to API here
      await storageService.registerUser(newUser);
      setCurrentUser(newUser);
      setViewMode(ViewMode.MEMBER);
    } catch (error: any) {
      alert(error.message);
    }
  };

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    setViewMode(ViewMode.MEMBER);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setViewMode(ViewMode.AUTH);
  };

  // Check-In Logic
  const handleUserCheckIn = async () => {
    if (!currentUser) return;

    const todayDate = new Date().toLocaleDateString();

    try {
      // Update in DB (Simulated)
      const updatedUser = await storageService.updateUserCheckIn(currentUser.id, todayDate);

      // Update Local State
      setCurrentUser(updatedUser);
    } catch (e) {
      console.error("Check-in failed", e);
    }
  };

  // Handle Admin Access
  const handlePinSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (pinInput === ADMIN_PIN) {
      setViewMode(ViewMode.ADMIN);
      setIsPinModalOpen(false);
      setPinInput('');
      setPinError(false);
    } else {
      setPinError(true);
      setPinInput('');
    }
  };

  return (
    <div className="min-h-screen w-full relative overflow-hidden flex flex-col">
      {/* Background Ambience */}
      <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] rounded-full bg-purple-900/30 blur-[120px] pointer-events-none" />
      <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] rounded-full bg-blue-900/30 blur-[120px] pointer-events-none" />

      {/* Main Content Area */}
      <main className="flex-1 flex flex-col items-center justify-start pt-10 px-4 pb-20 z-10">

        {viewMode === ViewMode.AUTH && (
          <AuthView 
            onLogin={handleLogin} 
            onRegister={handleRegister} 
          />
        )}

        {viewMode === ViewMode.ADMIN && (
          <AdminPanel 
            tracks={targetTracks} 
            onSave={handleSaveTracks} 
            onExit={() => setViewMode(currentUser ? ViewMode.MEMBER : ViewMode.AUTH)} 
          />
        )}

        {viewMode === ViewMode.MEMBER && currentUser && (
          <MemberView 
            tracks={targetTracks} 
            currentUser={currentUser}
            onCheckIn={handleUserCheckIn}
            onLogout={handleLogout}
          />
        )}
      </main>

      {/* Admin Trigger (Bottom Left) - Always visible unless inside Admin panel */}
      {viewMode !== ViewMode.ADMIN && (
        <button
          onClick={() => setIsPinModalOpen(true)}
          className="fixed bottom-6 left-6 p-3 rounded-full bg-white/5 hover:bg-white/10 text-gray-500 hover:text-white transition-all z-50 group"
          aria-label="Admin Access"
        >
          <Lock size={16} className="group-hover:opacity-100 opacity-50" />
        </button>
      )}

      {/* PIN Modal */}
      {isPinModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
          <div className="glass w-full max-w-sm p-6 rounded-2xl relative animate-bounce-in">
            <button 
              onClick={() => setIsPinModalOpen(false)}
              className="absolute top-4 right-4 text-gray-400 hover:text-white"
            >
              <X size={20} />
            </button>

            <h3 className="text-xl font-bold mb-4 text-center">Admin Access</h3>
            <p className="text-gray-400 text-sm text-center mb-6">Enter PIN to configure playlist.</p>

            <form onSubmit={handlePinSubmit} className="flex flex-col gap-4">
              <input 
                type="password" 
                maxLength={4}
                value={pinInput}
                onChange={(e) => {
                  setPinInput(e.target.value);
                  setPinError(false);
                }}
                className="bg-black/50 border border-white/20 rounded-xl px-4 py-3 text-center text-2xl tracking-[0.5em] focus:outline-none focus:border-purple-500 transition-colors"
                autoFocus
              />

              {pinError && (
                <p className="text-red-500 text-xs text-center">Incorrect PIN. Try '1234'.</p>
              )}

              <button 
                type="submit"
                className="bg-purple-600 hover:bg-purple-500 text-white rounded-xl py-3 font-bold mt-2 shadow-[0_0_10px_rgba(168,85,247,0.4)] transition-all flex justify-center items-center gap-2"
              >
                <Unlock size={18} />
                Unlock
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;

import React, { useState, useRef } from 'react';
import { User as UserIcon, Lock, Key, Music, ArrowRight, LogIn, Download, Upload, Settings, AlertTriangle, Check, X } from 'lucide-react';
import { User } from '../types';
import { storageService } from '../services/storage';

interface AuthViewProps {
  onLogin: (user: User) => void;
  onRegister: (newUser: User) => void;
  // usersDb prop removed as the service handles it internally now
}

export const AuthView: React.FC<AuthViewProps> = ({ onLogin, onRegister }) => {
  const [isRegistering, setIsRegistering] = useState(false);
  const [showDataModal, setShowDataModal] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  // Form States
  const [appUsername, setAppUsername] = useState('');
  const [password, setPassword] = useState('');
  const [lastFmUsername, setLastFmUsername] = useState('');
  const [lastFmApiKey, setLastFmApiKey] = useState('');

  const [error, setError] = useState<string | null>(null);
  const [successMsg, setSuccessMsg] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setIsLoading(true);

    if (!appUsername || !password) {
      setError('Username and Password are required.');
      setIsLoading(false);
      return;
    }

    try {
      if (isRegistering) {
        // REGISTER LOGIC via Service
        const newUser: User = {
          id: Date.now().toString(),
          appUsername,
          password,
          lastFmUsername: lastFmUsername || '', 
          lastFmApiKey: lastFmApiKey || '',
          lastCheckInDate: null
        };

        // Service throws error if username taken
        await storageService.registerUser(newUser);

        // Pass up to parent to set session
        onRegister(newUser);
      } else {
        // LOGIN LOGIC via Service
        const user = await storageService.loginUser(appUsername, password);
        onLogin(user);
      }
    } catch (err: any) {
      setError(err.message || 'Authentication failed');
    } finally {
      setIsLoading(false);
    }
  };

  // --- DATA MANAGEMENT LOGIC ---

  const handleExportData = () => {
    try {
      const data = storageService.exportData();

      const backupData = {
        version: 1,
        timestamp: new Date().toISOString(),
        users: data.users ? JSON.parse(data.users) : [],
        playlist: data.tracks ? JSON.parse(data.tracks) : [],
      };

      const blob = new Blob([JSON.stringify(backupData, null, 2)], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `streamguard_backup_${new Date().toISOString().slice(0, 10)}.json`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);

