            className={`w-full py-4 rounded-xl font-bold flex items-center justify-center gap-2 transition-all mt-4 text-white shadow-[0_0_20px_rgba(176,38,255,0.4)] ${
              isLoading ? 'bg-gray-600 cursor-not-allowed' : 'bg-gradient-to-r from-neon-purple to-pink-600 hover:scale-[1.02]'
            }`}
          >
            {isLoading ? 'Processing...' : (isRegistering ? <><ArrowRight size={20} /> Create Account</> : <><LogIn size={20} /> Login</>)}
          </button>
        </form>

        <div className="mt-6 text-center">
          <button 
            onClick={() => { setIsRegistering(!isRegistering); setError(null); }}
            className="text-gray-400 hover:text-white text-sm transition-colors hover:underline"
          >
            {isRegistering ? 'Already have an account? Login' : "Don't have an account? Register"}
          </button>
        </div>
      </div>
    </div>
  );
};

import { User, TargetTrack, CloudConfig, AppData } from '../types';
import { STORAGE_KEY, STORAGE_KEY_USERS, STORAGE_KEY_CLOUD, DEFAULT_TRACKS } from '../constants';

// --- CLOUD STORAGE SERVICE (JSONBin.io Adapter) ---

export const storageService = {

  // --- CONFIGURATION ---

  getCloudConfig(): CloudConfig | null {
    const stored = localStorage.getItem(STORAGE_KEY_CLOUD);
    return stored ? JSON.parse(stored) : null;
  },

  saveCloudConfig(config: CloudConfig) {
    localStorage.setItem(STORAGE_KEY_CLOUD, JSON.stringify(config));
  },

  disconnectCloud() {
    localStorage.removeItem(STORAGE_KEY_CLOUD);
  },

  // Verify connection validity before saving
  async verifyConnection(binId: string, apiKey: string): Promise<{valid: boolean; message?: string}> {
    try {
        const cleanBinId = binId.trim();
        const cleanApiKey = apiKey.trim();

        if (!cleanBinId || !cleanApiKey) return { valid: false, message: 'Bin ID and API Key are required' };

        const response = await fetch(`https://api.jsonbin.io/v3/b/${cleanBinId}/latest`, {
          method: 'GET',
          headers: {
            'X-Master-Key': cleanApiKey,
            'Content-Type': 'application/json'
          }
        });

        if (response.ok) return { valid: true };

        if (response.status === 401 || response.status === 403) return { valid: false, message: 'Invalid API Key or Access Denied' };
        if (response.status === 404) return { valid: false, message: 'Bin ID not found' };

        return { valid: false, message: `Connection failed: ${response.statusText}` };
    } catch (e: any) {
        return { valid: false, message: 'Network error or invalid configuration' };
    }
  },

  // --- INTERNAL HELPERS ---

  // Fetches the entire DB (Users + Tracks)
  async _fetchFullData(): Promise<AppData> {
    const config = this.getCloudConfig();

    // 1. CLOUD MODE
    if (config && config.enabled && config.binId && config.apiKey) {
      const cleanBinId = config.binId.trim();
      const cleanApiKey = config.apiKey.trim();

      try {
        const response = await fetch(`https://api.jsonbin.io/v3/b/${cleanBinId}/latest`, {
          method: 'GET',
          headers: {
            'X-Master-Key': cleanApiKey,
            'Content-Type': 'application/json'
          }
        });

        if (!response.ok) {
            if (response.status === 401 || response.status === 403) throw new Error('Cloud Auth Failed: Check API Key');
            if (response.status === 404) throw new Error('Cloud Error: Bin ID not found');
            throw new Error(`Cloud Sync Failed (${response.status})`);
        }

        const result = await response.json();
        // JSONBin v3 returns data inside a 'record' property
        return result.record as AppData;
      } catch (e: any) {
        console.error("Cloud Fetch Error:", e);
        throw new Error(e.message || "Could not connect to Cloud Database.");
      }
    } 

    // 2. LOCAL MODE
    else {
      const usersStr = localStorage.getItem(STORAGE_KEY_USERS);
      const tracksStr = localStorage.getItem(STORAGE_KEY);
      return {
        users: usersStr ? JSON.parse(usersStr) : [],
        tracks: tracksStr ? JSON.parse(tracksStr) : DEFAULT_TRACKS
      };
    }
  },

  // Saves the entire DB
  async _saveFullData(data: AppData): Promise<void> {
    const config = this.getCloudConfig();

    // 1. CLOUD MODE
    if (config && config.enabled && config.binId && config.apiKey) {
       const cleanBinId = config.binId.trim();
       const cleanApiKey = config.apiKey.trim();

       try {
        const response = await fetch(`https://api.jsonbin.io/v3/b/${cleanBinId}`, {
          method: 'PUT',
          headers: {
            'X-Master-Key': cleanApiKey,
            'Content-Type': 'application/json'
          },
          body: JSON.stringify(data)
        });

        if (!response.ok) throw new Error(`Cloud Save Failed (${response.status})`);

        // Also update local cache
        localStorage.setItem(STORAGE_KEY_USERS, JSON.stringify(data.users));
        localStorage.setItem(STORAGE_KEY, JSON.stringify(data.tracks));

      } catch (e) {
        console.error("Cloud Save Error:", e);
        throw new Error("Failed to save to Cloud.");
      }
    } 

    // 2. LOCAL MODE
    else {
      localStorage.setItem(STORAGE_KEY_USERS, JSON.stringify(data.users));
      localStorage.setItem(STORAGE_KEY, JSON.stringify(data.tracks));
    }
  },

  // --- PUBLIC METHODS (Abstracted) ---

  async getUsers(): Promise<User[]> {
    const data = await this._fetchFullData();
    // Initialize empty users array if new bin
    return data.users || [];
  },

  async registerUser(newUser: User): Promise<User> {
    const data = await this._fetchFullData();
    const users = data.users || [];

    if (users.some(u => u.appUsername.toLowerCase() === newUser.appUsername.toLowerCase())) {
      throw new Error('Username already taken');
    }

    const updatedUsers = [...users, newUser];
    const newData = { ...data, users: updatedUsers };

    await this._saveFullData(newData);
    return newUser;
  },

  async loginUser(username: string, password: string): Promise<User> {
    const data = await this._fetchFullData();
    const users = data.users || [];

    const user = users.find(u => 
      u.appUsername.toLowerCase() === username.toLowerCase() && 
      u.password === password
    );
    if (!user) throw new Error('Invalid credentials');
    return user;
  },

  async updateUserCheckIn(userId: string, dateString: string): Promise<User> {
    const data = await this._fetchFullData();
    const users = data.users || [];
    let updatedUser: User | null = null;

    const newUsers = users.map(u => {
      if (u.id === userId) {
        updatedUser = { ...u, lastCheckInDate: dateString };
        return updatedUser;
      }
      return u;
    });

    if (!updatedUser) throw new Error('User not found');

    await this._saveFullData({ ...data, users: newUsers });
    return updatedUser!;
  },

  // --- TRACK METHODS ---

  async getTracks(): Promise<TargetTrack[]> {
    const data = await this._fetchFullData();
    return data.tracks || DEFAULT_TRACKS;
  },

  async saveTracks(tracks: TargetTrack[]): Promise<void> {
    const data = await this._fetchFullData();
    await this._saveFullData({ ...data, tracks });
  },

  // --- BACKUP UTILS (Frontend Only) ---

  exportData() {
    return {
      users: localStorage.getItem(STORAGE_KEY_USERS),
      tracks: localStorage.getItem(STORAGE_KEY)
    };
  },

  importData(usersJson: string | null, tracksJson: string | null) {
    if (usersJson) localStorage.setItem(STORAGE_KEY_USERS, usersJson);
    if (tracksJson) localStorage.setItem(STORAGE_KEY, tracksJson);
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Trash2, Save, ArrowLeft, Plus, Settings, Database, Cloud, CloudOff, Download, Upload, ListMusic, Loader2 } from 'lucide-react';
import { TargetTrack, CloudConfig } from '../types';
import { storageService } from '../services/storage';

interface AdminPanelProps {
  tracks: TargetTrack[];
  onSave: (tracks: TargetTrack[]) => void;
  onExit: () => void;
}

export const AdminPanel: React.FC<AdminPanelProps> = ({ tracks, onSave, onExit }) => {
  const [activeTab, setActiveTab] = useState<'playlist' | 'settings'>('playlist');

  // Playlist State
  const [localTracks, setLocalTracks] = useState<TargetTrack[]>(tracks);
  const [newArtist, setNewArtist] = useState('');
  const [newTitle, setNewTitle] = useState('');

  // Settings State
  const [cloudConfig, setCloudConfig] = useState<CloudConfig>({ enabled: false, binId: '', apiKey: '' });
  const [settingsMsg, setSettingsMsg] = useState<string | null>(null);
  const [isVerifying, setIsVerifying] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    // Load existing cloud config when panel opens
    const config = storageService.getCloudConfig();
    if (config) {
      setCloudConfig(config);
    }
  }, []);

  // --- PLAYLIST LOGIC ---
  const handleAddTrack = () => {
    if (!newArtist.trim() || !newTitle.trim()) return;
    const newTrack: TargetTrack = {
      id: Date.now().toString(),
      artist: newArtist.trim(),
      title: newTitle.trim(),
    };
    setLocalTracks([...localTracks, newTrack]);
    setNewArtist('');
    setNewTitle('');
  };

  const handleRemoveTrack = (id: string) => {
    setLocalTracks(localTracks.filter(t => t.id !== id));
  };

  const handleSavePlaylist = () => {
    onSave(localTracks);
  };

  // --- SETTINGS LOGIC ---
  const handleSaveCloudConfig = async () => {
    setSettingsMsg(null);
    if (!cloudConfig.binId || !cloudConfig.apiKey) {
        setSettingsMsg('Please enter both Bin ID and API Key.');
        return;
    }

    setIsVerifying(true);

    // Verify connection first
    const verification = await storageService.verifyConnection(cloudConfig.binId, cloudConfig.apiKey);

    setIsVerifying(false);

    if (verification.valid) {
      const newConfig = { ...cloudConfig, enabled: true };
      storageService.saveCloudConfig(newConfig);
      setCloudConfig(newConfig);
      setSettingsMsg('SUCCESS: Cloud Connected! Please reload the app.');
    } else {
      setSettingsMsg(`ERROR: ${verification.message}`);
    }
  };

  const handleDisconnectCloud = () => {
    storageService.disconnectCloud();
    setCloudConfig({ enabled: false, binId: '', apiKey: '' });
    setSettingsMsg('Cloud Disconnected. Using Local Storage.');
  };

  const handleExportData = () => {
    try {
      const data = storageService.exportData();
      const backupData = {
        version: 1,
        timestamp: new Date().toISOString(),
        users: data.users ? JSON.parse(data.users) : [],
        playlist: data.tracks ? JSON.parse(data.tracks) : [],
      };
      const blob = new Blob([JSON.stringify(backupData, null, 2)], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `streamguard_admin_backup.json`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
      setSettingsMsg('Backup downloaded.');
    } catch (err) { setSettingsMsg('Failed to generate backup.'); }
  };

  const handleImportClick = () => { fileInputRef.current?.click(); };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        if (window.confirm('WARNING: This will overwrite ALL data (users & playlist). Continue?')) {
            storageService.importData(
              json.users ? JSON.stringify(json.users) : null,
              json.playlist ? JSON.stringify(json.playlist) : null
            );
            alert('Data restored successfully. Reloading...');
            window.location.reload();
        }
      } catch (err) { alert('Invalid backup file.'); }
    };
    reader.readAsText(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="w-full max-w-3xl mx-auto p-6 animate-fade-in">
      <div className="flex items-center justify-between mb-8">
        <h2 className="text-3xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-purple-400 to-pink-600">
          Admin Dashboard
        </h2>
        <button 
          onClick={onExit}
          className="flex items-center gap-2 px-4 py-2 rounded-lg bg-white/10 hover:bg-white/20 transition-all text-sm font-medium"
        >
          <ArrowLeft size={16} />
          Exit Admin
        </button>
      </div>

      {/* Tabs */}
      <div className="flex gap-4 mb-6">
        <button 
            onClick={() => setActiveTab('playlist')}
            className={`flex-1 py-3 rounded-xl font-bold flex items-center justify-center gap-2 transition-all ${activeTab === 'playlist' ? 'bg-purple-600 text-white shadow-lg shadow-purple-900/40' : 'bg-white/5 text-gray-400 hover:bg-white/10'}`}
        >
            <ListMusic size={18} /> Playlist Manager
        </button>
        <button 
            onClick={() => setActiveTab('settings')}
            className={`flex-1 py-3 rounded-xl font-bold flex items-center justify-center gap-2 transition-all ${activeTab === 'settings' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/40' : 'bg-white/5 text-gray-400 hover:bg-white/10'}`}
        >
            <Settings size={18} /> System Settings
        </button>
      </div>

      {activeTab === 'playlist' && (
        <>
            {/* Add New Track Form */}
            <div className="glass p-6 rounded-2xl mb-8 shadow-lg shadow-purple-900/20">
                <h3 className="text-lg font-semibold text-purple-300 mb-4">Add Target Track</h3>
                <div className="flex flex-col md:flex-row gap-4">
                <input 
                    type="text" 
                    placeholder="Artist Name"
                    value={newArtist}
                    onChange={(e) => setNewArtist(e.target.value)}
                    className="flex-1 bg-black/40 border border-white/10 rounded-xl px-4 py-3 focus:outline-none focus:border-purple-500 transition-colors"
                />
                <input 
                    type="text" 
                    placeholder="Track Title"
                    value={newTitle}
                    onChange={(e) => setNewTitle(e.target.value)}
                    className="flex-1 bg-black/40 border border-white/10 rounded-xl px-4 py-3 focus:outline-none focus:border-purple-500 transition-colors"
                />
                <button 
                    onClick={handleAddTrack}
                    className="bg-purple-600 hover:bg-purple-500 text-white rounded-xl px-6 py-3 font-bold transition-all shadow-[0_0_15px_rgba(168,85,247,0.4)] flex items-center justify-center gap-2"
                >
                    <Plus size={20} />
                    Add
                </button>
                </div>
            </div>

            {/* Track List */}
            <div className="glass p-6 rounded-2xl shadow-lg shadow-purple-900/20">
                <div className="flex justify-between items-center mb-4">
                <h3 className="text-lg font-semibold text-purple-300">Current Playlist ({localTracks.length})</h3>
                <button 
                    onClick={handleSavePlaylist}
                    className="flex items-center gap-2 bg-green-500/80 hover:bg-green-500 text-white px-4 py-2 rounded-lg font-medium transition-all shadow-[0_0_15px_rgba(74,222,128,0.4)]"
                >
                    <Save size={18} />
                    Save Changes
                </button>
                </div>

                <div className="space-y-3">
                {localTracks.length === 0 ? (
                    <p className="text-center text-gray-400 py-8 italic">No tracks in the playlist.</p>
                ) : (
                    localTracks.map((track) => (
                    <div key={track.id} className="flex items-center justify-between p-4 bg-black/30 rounded-xl border border-white/5 hover:border-purple-500/30 transition-all">
                        <div>
                        <div className="font-bold text-white">{track.title}</div>
                        <div className="text-sm text-gray-400">{track.artist}</div>
                        </div>
                        <button 
                        onClick={() => handleRemoveTrack(track.id)}
                        className="text-red-400 hover:text-red-300 hover:bg-red-900/20 p-2 rounded-lg transition-colors"
                        >
                        <Trash2 size={20} />
                        </button>
                    </div>
                    ))
                )}
                </div>
            </div>
        </>
      )}

      {activeTab === 'settings' && (
        <div className="animate-fade-in space-y-6">

            {/* Cloud Config Section */}
            <div className="glass p-6 rounded-2xl border border-blue-500/20">
                <h3 className="text-xl font-bold mb-4 flex items-center gap-2 text-blue-400">
                    <Cloud /> Database Connection
                </h3>
                <p className="text-sm text-gray-400 mb-6">
                    Connect to JSONBin.io to allow users to sync data across different devices.
                </p>

                <div className="space-y-4">
                    <div>
                        <label className="text-xs font-bold text-gray-500 block mb-1">Bin ID</label>
                        <input 
                            type="text" 
                            value={cloudConfig.binId} 
                            onChange={(e) => setCloudConfig({...cloudConfig, binId: e.target.value})}
                            className="w-full bg-black/50 border border-white/10 rounded-lg p-3 text-white focus:border-blue-500 focus:outline-none"
                            placeholder="e.g. 65d4f..."
                        />
                    </div>
                    <div>
                        <label className="text-xs font-bold text-gray-500 block mb-1">Master Key (X-Master-Key)</label>
                        <input 
                            type="password" 
                            value={cloudConfig.apiKey} 
                            onChange={(e) => setCloudConfig({...cloudConfig, apiKey: e.target.value})}
                            className="w-full bg-black/50 border border-white/10 rounded-lg p-3 text-white focus:border-blue-500 focus:outline-none"
                            placeholder="e.g. $2a$10$..."
                        />
                    </div>

                    <div className="flex gap-4 pt-2">
                        <button 
                            onClick={handleSaveCloudConfig}
                            disabled={isVerifying}
                            className={`flex-1 py-3 rounded-xl font-bold text-white transition-colors flex items-center justify-center gap-2 ${isVerifying ? 'bg-blue-800' : 'bg-blue-600 hover:bg-blue-500'}`}
                        >
                            {isVerifying && <Loader2 className="animate-spin" size={18} />}
                            {cloudConfig.enabled ? 'Update Connection' : 'Connect Cloud'}
                        </button>

                        {cloudConfig.enabled && !isVerifying && (
                            <button 
                                onClick={handleDisconnectCloud}
                                className="px-6 py-3 bg-red-900/50 hover:bg-red-900 text-red-300 rounded-xl font-bold transition-colors flex items-center gap-2"
                            >
                                <CloudOff size={18} /> Disconnect
                            </button>
                        )}
                    </div>
                </div>
            </div>

            {/* Backup Section */}
            <div className="glass p-6 rounded-2xl border border-white/10">
                <h3 className="text-xl font-bold mb-4 flex items-center gap-2 text-white">
                    <Database /> Manual Backup
                </h3>
                <p className="text-sm text-gray-400 mb-6">
                    Download a local copy of the entire database (Users + Playlist) or restore from a file.
                </p>

                <div className="grid grid-cols-2 gap-4">
                    <button 
                        onClick={handleExportData}
                        className="py-4 bg-white/5 border border-white/10 hover:bg-white/10 rounded-xl flex flex-col items-center justify-center gap-2 transition-all"
                    >
                        <Download size={24} className="text-neon-green" /> 
                        <span className="font-bold">Backup to JSON</span>
                    </button>

                    <div className="relative">
                        <input type="file" ref={fileInputRef} onChange={handleFileChange} accept=".json" className="hidden" />
                        <button 
                            onClick={handleImportClick}
                            className="w-full h-full py-4 bg-white/5 border border-white/10 hover:bg-white/10 rounded-xl flex flex-col items-center justify-center gap-2 transition-all"
                        >
                            <Upload size={24} className="text-orange-400" /> 
                            <span className="font-bold">Restore from JSON</span>
                        </button>
                    </div>
                </div>
            </div>

            {settingsMsg && (
                <div className={`p-4 rounded-xl text-center font-medium border animate-pulse ${
                    settingsMsg.includes('SUCCESS') ? 'bg-green-900/20 border-green-500/30 text-green-300' : 
                    settingsMsg.includes('ERROR') ? 'bg-red-900/20 border-red-500/30 text-red-300' :
                    'bg-white/10 border-white/20 text-white'
                }`}>
                    {settingsMsg}
                </div>
            )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Lock, Unlock, X } from 'lucide-react';
import { ViewMode, TargetTrack, User } from './types';
import { ADMIN_PIN } from './constants';
import { AdminPanel } from './components/AdminPanel';
import { MemberView } from './components/MemberView';
import { AuthView } from './components/AuthView';
import { storageService } from './services/storage';

function App() {
  const [viewMode, setViewMode] = useState<ViewMode>(ViewMode.AUTH);
  const [targetTracks, setTargetTracks] = useState<TargetTrack[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  // Pin Modal State
  const [isPinModalOpen, setIsPinModalOpen] = useState(false);
  const [pinInput, setPinInput] = useState('');
  const [pinError, setPinError] = useState(false);

  // Initialize Data
  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    try {
      const tracks = await storageService.getTracks();
      setTargetTracks(tracks);
    } catch (e) {
      console.error("Failed to load data", e);
    }
  };

  // Save tracks handler
  const handleSaveTracks = async (newTracks: TargetTrack[]) => {
    await storageService.saveTracks(newTracks);
    setTargetTracks(newTracks);
    alert('Playlist updated successfully!');
  };

  // Auth Handlers
  const handleRegister = async (newUser: User) => {
    try {
      // In a real DB app, you'd send data to API here
      await storageService.registerUser(newUser);
      setCurrentUser(newUser);
      setViewMode(ViewMode.MEMBER);
    } catch (error: any) {
      alert(error.message);
    }
  };

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    setViewMode(ViewMode.MEMBER);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setViewMode(ViewMode.AUTH);
  };

  // Check-In Logic
  const handleUserCheckIn = async () => {
    if (!currentUser) return;

    const todayDate = new Date().toLocaleDateString();

    try {
      // Update in DB (Simulated)
      const updatedUser = await storageService.updateUserCheckIn(currentUser.id, todayDate);

      // Update Local State
      setCurrentUser(updatedUser);
    } catch (e) {
      console.error("Check-in failed", e);
    }
  };

  // Handle Admin Access
  const handlePinSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (pinInput === ADMIN_PIN) {
      setViewMode(ViewMode.ADMIN);
      setIsPinModalOpen(false);
      setPinInput('');
      setPinError(false);
    } else {
      setPinError(true);
      setPinInput('');
    }
  };

  return (
    <div className="min-h-screen w-full relative overflow-hidden flex flex-col">
      {/* Background Ambience */}
      <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] rounded-full bg-purple-900/30 blur-[120px] pointer-events-none" />
      <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] rounded-full bg-blue-900/30 blur-[120px] pointer-events-none" />

      {/* Main Content Area */}
      <main className="flex-1 flex flex-col items-center justify-start pt-10 px-4 pb-20 z-10">

        {viewMode === ViewMode.AUTH && (
          <AuthView 
            onLogin={handleLogin} 
            onRegister={handleRegister} 
            onOpenAdmin={() => setIsPinModalOpen(true)}
          />
        )}

        {viewMode === ViewMode.ADMIN && (
          <AdminPanel 
            tracks={targetTracks} 
            onSave={handleSaveTracks} 
            onExit={() => setViewMode(currentUser ? ViewMode.MEMBER : ViewMode.AUTH)} 
          />
        )}

        {viewMode === ViewMode.MEMBER && currentUser && (
          <MemberView 
            tracks={targetTracks} 
            currentUser={currentUser}
            onCheckIn={handleUserCheckIn}
            onLogout={handleLogout}
          />
        )}
      </main>

      {/* Admin Trigger (Bottom Left) - Always visible unless inside Admin panel */}
      {viewMode !== ViewMode.ADMIN && (
        <button
          onClick={() => setIsPinModalOpen(true)}
          className="fixed bottom-6 left-6 p-3 rounded-full bg-white/5 hover:bg-white/10 text-gray-500 hover:text-white transition-all z-50 group"
          aria-label="Admin Access"
        >
          <Lock size={16} className="group-hover:opacity-100 opacity-50" />
        </button>
      )}

      {/* PIN Modal */}
      {isPinModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
          <div className="glass w-full max-w-sm p-6 rounded-2xl relative animate-bounce-in">
            <button 
              onClick={() => setIsPinModalOpen(false)}
              className="absolute top-4 right-4 text-gray-400 hover:text-white"
            >
              <X size={20} />
            </button>

            <h3 className="text-xl font-bold mb-4 text-center">Admin Access</h3>
            <p className="text-gray-400 text-sm text-center mb-6">Enter PIN to configure playlist.</p>

            <form onSubmit={handlePinSubmit} className="flex flex-col gap-4">
              <input 
                type="password" 
                maxLength={4}
                value={pinInput}
                onChange={(e) => {
                  setPinInput(e.target.value);
                  setPinError(false);
                }}
                className="bg-black/50 border border-white/20 rounded-xl px-4 py-3 text-center text-2xl tracking-[0.5em] focus:outline-none focus:border-purple-500 transition-colors"
                autoFocus
              />

              {pinError && (
                <p className="text-red-500 text-xs text-center">Incorrect PIN. Try '1234'.</p>
              )}

              <button 
                type="submit"
                className="bg-purple-600 hover:bg-purple-500 text-white rounded-xl py-3 font-bold mt-2 shadow-[0_0_10px_rgba(168,85,247,0.4)] transition-all flex justify-center items-center gap-2"
              >
                <Unlock size={18} />
                Unlock
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;

