                                                       <CheckCircle2 size={14} /> Checked In
                                                   </div>
                                               ) : (
                                                   <div className="flex items-center gap-1 bg-red-900/20 text-gray-400 px-3 py-1 rounded-full text-xs font-bold border border-white/5">
                                                        <Clock size={14} /> Pending
                                                   </div>
