import { User, TargetTrack, CloudConfig, AppData } from '../types';
import { STORAGE_KEY, STORAGE_KEY_USERS, STORAGE_KEY_CLOUD, STORAGE_KEY_SPOTIFY, DEFAULT_TRACKS, DEFAULT_CLOUD_CONFIG, DEFAULT_SPOTIFY_ID } from '../constants';

// --- CLOUD STORAGE SERVICE (JSONBin.io Adapter) ---

export const storageService = {

  // --- CONFIGURATION ---

  getCloudConfig(): CloudConfig | null {
    // 1. Cek LocalStorage (Settingan Manual User)
    const stored = localStorage.getItem(STORAGE_KEY_CLOUD);
    if (stored) {
      return JSON.parse(stored);
    }

    // 2. Jika LocalStorage kosong, gunakan Default Config dari constants.ts
    // Ini agar user baru/incognito langsung terkoneksi
    if (DEFAULT_CLOUD_CONFIG.binId && DEFAULT_CLOUD_CONFIG.apiKey) {
      return DEFAULT_CLOUD_CONFIG;
    }

    return null;
  },

  saveCloudConfig(config: CloudConfig) {
    localStorage.setItem(STORAGE_KEY_CLOUD, JSON.stringify(config));
  },

  disconnectCloud() {
    localStorage.removeItem(STORAGE_KEY_CLOUD);
    // Note: Jika DEFAULT_CLOUD_CONFIG diisi di constants.ts, 
    // aplikasi akan tetap mencoba connect menggunakan default tersebut 
    // meskipun user menekan disconnect (karena logika fallback di getCloudConfig).
  },

  // Verify connection validity before saving
  async verifyConnection(binId: string, apiKey: string): Promise<{valid: boolean; message?: string}> {
    try {
        const cleanBinId = binId.trim();
        const cleanApiKey = apiKey.trim();

        if (!cleanBinId || !cleanApiKey) return { valid: false, message: 'Bin ID and API Key are required' };

        const response = await fetch(`https://api.jsonbin.io/v3/b/${cleanBinId}/latest`, {
          method: 'GET',
          headers: {
            'X-Master-Key': cleanApiKey,
            'Content-Type': 'application/json'
          }
        });

        if (response.ok) return { valid: true };

        if (response.status === 401 || response.status === 403) return { valid: false, message: 'Invalid API Key or Access Denied' };
        if (response.status === 404) return { valid: false, message: 'Bin ID not found' };

        return { valid: false, message: `Connection failed: ${response.statusText}` };
    } catch (e: any) {
        return { valid: false, message: 'Network error or invalid configuration' };
    }
  },

  // --- INTERNAL HELPERS ---

  // Fetches the entire DB (Users + Tracks + Settings)
  async _fetchFullData(): Promise<AppData> {
    const config = this.getCloudConfig();

    // 1. CLOUD MODE
    if (config && config.enabled && config.binId && config.apiKey) {
      const cleanBinId = config.binId.trim();
      const cleanApiKey = config.apiKey.trim();

      try {
        const response = await fetch(`https://api.jsonbin.io/v3/b/${cleanBinId}/latest`, {
          method: 'GET',
          headers: {
            'X-Master-Key': cleanApiKey,
            'Content-Type': 'application/json'
          }
        });

        if (!response.ok) {
            if (response.status === 401 || response.status === 403) throw new Error('Cloud Auth Failed: Check API Key');
            if (response.status === 404) throw new Error('Cloud Error: Bin ID not found');
            throw new Error(`Cloud Sync Failed (${response.status})`);
        }

        const result = await response.json();
        // JSONBin v3 returns data inside a 'record' property
        const record = result.record || {};

        // Normalize Data: Ensure arrays are actually arrays
        return {
            users: Array.isArray(record.users) ? record.users : [],
            tracks: Array.isArray(record.tracks) ? record.tracks : (record.tracks || DEFAULT_TRACKS),
            spotifyPlaylistId: record.spotifyPlaylistId || DEFAULT_SPOTIFY_ID
        };

      } catch (e: any) {
        console.error("Cloud Fetch Error:", e);
        throw new Error(e.message || "Could not connect to Cloud Database.");
      }
    } 

    // 2. LOCAL MODE
    else {
      const usersStr = localStorage.getItem(STORAGE_KEY_USERS);
      const tracksStr = localStorage.getItem(STORAGE_KEY);
      const spotifyIdStr = localStorage.getItem(STORAGE_KEY_SPOTIFY);

      let users = [];
      let tracks = DEFAULT_TRACKS;

      try {
          if (usersStr) {
              const parsed = JSON.parse(usersStr);
              if (Array.isArray(parsed)) users = parsed;
          }
      } catch (e) { console.error("Error parsing local users", e); }

      try {
          if (tracksStr) {
              const parsed = JSON.parse(tracksStr);
              if (Array.isArray(parsed)) tracks = parsed;
          }
      } catch (e) { console.error("Error parsing local tracks", e); }

      return {
        users,
        tracks,
        spotifyPlaylistId: spotifyIdStr || DEFAULT_SPOTIFY_ID
      };
    }
  },

  // Saves the entire DB
  async _saveFullData(data: AppData): Promise<void> {
    const config = this.getCloudConfig();

    // 1. CLOUD MODE
    if (config && config.enabled && config.binId && config.apiKey) {
       const cleanBinId = config.binId.trim();
       const cleanApiKey = config.apiKey.trim();

       try {
        const response = await fetch(`https://api.jsonbin.io/v3/b/${cleanBinId}`, {
          method: 'PUT',
          headers: {
            'X-Master-Key': cleanApiKey,
            'Content-Type': 'application/json'
          },
          body: JSON.stringify(data)
        });

        if (!response.ok) throw new Error(`Cloud Save Failed (${response.status})`);

        // Also update local cache
        localStorage.setItem(STORAGE_KEY_USERS, JSON.stringify(data.users));
        localStorage.setItem(STORAGE_KEY, JSON.stringify(data.tracks));
        if (data.spotifyPlaylistId) localStorage.setItem(STORAGE_KEY_SPOTIFY, data.spotifyPlaylistId);

      } catch (e) {
        console.error("Cloud Save Error:", e);
        throw new Error("Failed to save to Cloud.");
      }
    } 

    // 2. LOCAL MODE
    else {
      localStorage.setItem(STORAGE_KEY_USERS, JSON.stringify(data.users));
      localStorage.setItem(STORAGE_KEY, JSON.stringify(data.tracks));
      if (data.spotifyPlaylistId) localStorage.setItem(STORAGE_KEY_SPOTIFY, data.spotifyPlaylistId);
    }
  },

  // --- PUBLIC METHODS (Abstracted) ---

  async getUsers(): Promise<User[]> {
    const data = await this._fetchFullData();
    // Safety: ensure it is always an array
    return Array.isArray(data.users) ? data.users : [];
  },

  async registerUser(newUser: User): Promise<User> {
    const data = await this._fetchFullData();
    const users = Array.isArray(data.users) ? data.users : [];

    if (users.some(u => u.appUsername.toLowerCase() === newUser.appUsername.toLowerCase())) {
      throw new Error('Username already taken');
    }

    const updatedUsers = [...users, newUser];
    const newData = { ...data, users: updatedUsers };

    await this._saveFullData(newData);
    return newUser;
  },

  async loginUser(username: string, password: string): Promise<User> {
    const data = await this._fetchFullData();
    const users = Array.isArray(data.users) ? data.users : [];

    // This .find is likely where "find is not a function" happened if users wasn't an array
    const user = users.find(u => 
      u.appUsername.toLowerCase() === username.toLowerCase() && 
      u.password === password
    );
    if (!user) throw new Error('Invalid credentials');
    return user;
  },

  async updateUserCheckIn(userId: string, dateString: string): Promise<User> {
    const data = await this._fetchFullData();
    const users = Array.isArray(data.users) ? data.users : [];
    let updatedUser: User | null = null;

    const newUsers = users.map(u => {
      if (u.id === userId) {
        updatedUser = { ...u, lastCheckInDate: dateString };
        return updatedUser;
      }
      return u;
    });

    if (!updatedUser) throw new Error('User not found');

    await this._saveFullData({ ...data, users: newUsers });
    return updatedUser!;
  },

  // --- TRACK METHODS ---

  async getTracks(): Promise<TargetTrack[]> {
    const data = await this._fetchFullData();
    return Array.isArray(data.tracks) ? data.tracks : DEFAULT_TRACKS;
  },

  async saveTracks(tracks: TargetTrack[]): Promise<void> {
    const data = await this._fetchFullData();
    await this._saveFullData({ ...data, tracks });
  },

  // --- SPOTIFY CONFIG ---

  async getSpotifyId(): Promise<string> {
    const data = await this._fetchFullData();
    return data.spotifyPlaylistId || DEFAULT_SPOTIFY_ID;
  },

  async saveSpotifyId(id: string): Promise<void> {
    const data = await this._fetchFullData();
    await this._saveFullData({ ...data, spotifyPlaylistId: id });
  },

  // --- BACKUP UTILS (Frontend Only) ---

  exportData() {
    return {
      users: localStorage.getItem(STORAGE_KEY_USERS),
      tracks: localStorage.getItem(STORAGE_KEY),
      spotify: localStorage.getItem(STORAGE_KEY_SPOTIFY)
    };
  },

  importData(usersJson: string | null, tracksJson: string | null) {
    if (usersJson) localStorage.setItem(STORAGE_KEY_USERS, usersJson);
    if (tracksJson) localStorage.setItem(STORAGE_KEY, tracksJson);
  }
};

import React, { useState, useEffect } from 'react';
import { CheckCircle2, Circle, RefreshCw, Trophy, AlertCircle, Clock, CalendarCheck, LogOut, User as UserIcon, X, Music, ExternalLink } from 'lucide-react';
import { TargetTrack, User } from '../types';
import { fetchRecentTracks } from '../services/lastFmService';

interface MemberViewProps {
  tracks: TargetTrack[];
  currentUser: User;
  spotifyId: string; // Add this prop
  onCheckIn: () => void; // Parent handles the DB update
  onLogout: () => void;
}

export const MemberView: React.FC<MemberViewProps> = ({ tracks, currentUser, spotifyId, onCheckIn, onLogout }) => {
  const [isLoading, setIsLoading] = useState(false);
  const [synced, setSynced] = useState(false);

  const [matchedStatus, setMatchedStatus] = useState<Record<string, string>>({});
  const [error, setError] = useState<string | null>(null);
  const [showReward, setShowReward] = useState(false);
  const [hasCheckedInToday, setHasCheckedInToday] = useState(false);

  // Initialize Check-in status based on currentUser data
  useEffect(() => {
    const todayDate = new Date().toLocaleDateString();

    // Check user's specific last check-in date
    if (currentUser.lastCheckInDate === todayDate) {
      setHasCheckedInToday(true);
    } else {
      setHasCheckedInToday(false);
    }
  }, [currentUser]); // Re-run if user changes or updates

  const calculateProgress = () => {
    if (tracks.length === 0) return 0;
    const matchedCount = tracks.filter(t => matchedStatus[t.id]).length;
    return Math.round((matchedCount / tracks.length) * 100);
  };

  const handleSync = async () => {
    if (!currentUser.lastFmUsername) {
      setError('No Last.fm username found in profile.');
      return;
    }

    setIsLoading(true);
    setError(null);

    try {
      // Use credentials from the logged-in user
      const recentTracks = await fetchRecentTracks(currentUser.lastFmUsername, currentUser.lastFmApiKey);

      const newMatches: Record<string, string> = {};

      tracks.forEach(target => {
        const tArtist = target.artist.toLowerCase();
        const tTitle = target.title.toLowerCase();

        const foundTrack = recentTracks.find(recent => {
          const rArtist = recent.artist['#text'].toLowerCase();
          const rTitle = recent.name.toLowerCase();
          return rArtist.includes(tArtist) && rTitle.includes(tTitle);
        });

        if (foundTrack) {
          let timeDisplay = 'Just now';
          if (foundTrack.date) {
            timeDisplay = foundTrack.date['#text'];
          } else if (foundTrack['@attr']?.nowplaying === 'true') {
            timeDisplay = 'Listening Now...';
          }
          newMatches[target.id] = timeDisplay;
        }
      });

      setMatchedStatus(newMatches);
      setSynced(true);
    } catch (err: any) {
      setError(err.message || 'Failed to sync. Please check API Key in your profile.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleClaim = () => {
    // Call parent to update database
    onCheckIn(); 
    setHasCheckedInToday(true);
    setShowReward(true);
  };

  const progress = calculateProgress();
  const isComplete = progress === 100 && tracks.length > 0;

  const renderButton = () => {
    if (hasCheckedInToday) {
      return (
        <button 
          disabled
          className="w-full py-4 rounded-2xl font-bold text-lg flex items-center justify-center gap-3 bg-green-900/20 text-green-400 border border-green-500/30 cursor-not-allowed opacity-80"
        >
          <CalendarCheck size={24} />
          Checked In for Today
        </button>
      );
    }

    if (isComplete) {
      return (
        <button 
          onClick={handleClaim}
          className="w-full py-4 rounded-2xl font-bold text-lg flex items-center justify-center gap-3 transition-all duration-500 bg-gradient-to-r from-neon-purple to-pink-600 text-white shadow-[0_0_30px_rgba(176,38,255,0.6)] scale-100 hover:scale-[1.02] cursor-pointer"
        >
          <Trophy size={24} className="text-yellow-300" />
          CLAIM DAILY CHECK-IN
        </button>
      );
    }

    return (
      <button 
        disabled
        className="w-full py-4 rounded-2xl font-bold text-lg flex items-center justify-center gap-3 bg-white/5 text-gray-500 cursor-not-allowed border border-white/5"
      >
        <Trophy size={24} />
        Complete 100% to Check-In
      </button>
    );
  };

  return (
    <div className="w-full max-w-md mx-auto p-4 flex flex-col items-center">

      {/* User Header */}
      <div className="w-full flex justify-between items-center mb-6 bg-white/5 p-4 rounded-2xl border border-white/10">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-full bg-gradient-to-r from-blue-500 to-purple-500 flex items-center justify-center font-bold text-lg uppercase">
            {currentUser.appUsername.charAt(0)}
          </div>
          <div>
            <div className="text-sm text-gray-400">Logged in as</div>
            <div className="font-bold text-white leading-none">{currentUser.appUsername}</div>
            <div className="text-xs text-neon-green mt-1 flex items-center gap-1">
              <UserIcon size={10} /> {currentUser.lastFmUsername}
            </div>
          </div>
        </div>
        <button 
          onClick={onLogout}
          className="p-2 hover:bg-white/10 rounded-full text-gray-400 hover:text-white transition-colors"
          title="Logout"
        >
          <LogOut size={20} />
        </button>
      </div>

      <div className="mb-4 text-center">
        <h1 className="text-4xl font-extrabold tracking-tight text-transparent bg-clip-text bg-gradient-to-r from-neon-green to-blue-400 drop-shadow-sm">
          StreamGuard
        </h1>
      </div>

      {/* Sync Button Only (No Inputs) */}
      <div className="w-full glass p-6 rounded-2xl mb-6 shadow-[0_0_30px_rgba(0,0,0,0.3)]">
        <button 
          onClick={handleSync}
          disabled={isLoading}
          className={`w-full py-3 rounded-xl font-bold flex items-center justify-center gap-2 transition-all ${
            isLoading 
              ? 'bg-gray-600 cursor-not-allowed' 
              : 'bg-gradient-to-r from-blue-600 to-blue-500 hover:from-blue-500 hover:to-blue-400 shadow-[0_0_15px_rgba(59,130,246,0.5)]'
          }`}
        >
          <RefreshCw size={20} className={isLoading ? 'animate-spin' : ''} />
          {isLoading ? 'Sync Progress' : 'Check Streams'}
        </button>

        {error && (
            <div className="mt-3 flex items-center gap-2 text-red-400 text-sm bg-red-900/20 p-2 rounded-lg">
                <AlertCircle size={16} />
                {error}
            </div>
        )}

        {/* Spotify Link Button */}
        <div className="mt-6 pt-6 border-t border-white/10">
            <h4 className="text-xs text-gray-400 font-bold uppercase mb-3 flex items-center gap-2">
                <Music size={12} className="text-green-500" /> Target Playlist
            </h4>
            <a 
                href={`https://open.spotify.com/playlist/${spotifyId}`}
                target="_blank"
                rel="noopener noreferrer"
                className="w-full py-3 px-4 rounded-xl bg-[#1DB954] hover:bg-[#1ed760] text-black font-bold flex items-center justify-center gap-2 transition-all shadow-[0_0_15px_rgba(29,185,84,0.4)] hover:scale-[1.02]"
            >
                <Music size={20} fill="currentColor" />
                Open Playlist in Spotify
                <ExternalLink size={16} className="opacity-60 ml-1" />
            </a>
        </div>
      </div>

      {synced && (
        <div className="w-full animate-fade-in-up">
          {/* Progress Bar */}
          <div className="glass p-6 rounded-2xl mb-6">
            <div className="flex justify-between items-end mb-2">
              <span className="text-gray-400 font-medium">Daily Goal</span>
              <span className={`text-2xl font-bold ${isComplete ? 'text-neon-green' : 'text-white'}`}>
                {progress}%
              </span>
            </div>
            <div className="h-4 w-full bg-black/50 rounded-full overflow-hidden border border-white/5">
              <div 
                className="h-full bg-gradient-to-r from-neon-green to-emerald-600 transition-all duration-1000 ease-out"
                style={{ width: `${progress}%` }}
              />
            </div>
          </div>

          {/* Track List */}
          <div className="space-y-3 mb-8">
            {tracks.length === 0 ? (
                <div className="text-center text-gray-500 py-4">Admin hasn't set any tracks yet.</div>
            ) : (
                tracks.map((track) => {
                const matchTime = matchedStatus[track.id];
                const isListened = !!matchTime;

                return (
                    <div 
                    key={track.id} 
                    className={`flex items-center justify-between p-4 rounded-xl border transition-all duration-300 ${
                        isListened 
                        ? 'bg-green-900/10 border-green-500/30 shadow-[0_0_10px_rgba(0,255,65,0.1)]' 
                        : 'bg-white/5 border-white/5 opacity-80'
                    }`}
                    >
                    <div className="flex-1 pr-4">
                        <div className={`font-bold flex flex-wrap items-center gap-2 ${isListened ? 'text-green-300' : 'text-white'}`}>
                        <span>{track.title}</span>
                        {isListened && (
                             <span className="text-[10px] font-normal text-neon-green bg-green-900/40 px-2 py-0.5 rounded-full flex items-center gap-1 border border-green-500/20">
                                <Clock size={10} /> {matchTime}
                             </span>
                        )}
                        </div>
                        <div className="text-sm text-gray-400">{track.artist}</div>
                    </div>
                    <div className="flex-shrink-0">
                        {isListened ? (
                        <CheckCircle2 className="text-neon-green drop-shadow-[0_0_8px_rgba(0,255,65,0.8)]" size={28} />
                        ) : (
                        <Circle className="text-gray-600" size={28} />
                        )}
                    </div>
                    </div>
                );
                })
            )}
          </div>

          {renderButton()}

        </div>
      )}

      {/* Reward Modal */}
      {showReward && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/90 backdrop-blur-md p-4 animate-fade-in">
            <div className="glass max-w-sm w-full p-8 rounded-3xl text-center relative border border-neon-purple/50 shadow-[0_0_50px_rgba(176,38,255,0.3)]">
                <button 
                    onClick={() => setShowReward(false)}
                    className="absolute top-4 right-4 text-gray-400 hover:text-white"
                >
                    <X size={24} />
                </button>

                <div className="mx-auto w-24 h-24 bg-gradient-to-br from-yellow-300 to-yellow-600 rounded-full flex items-center justify-center mb-6 shadow-[0_0_30px_rgba(234,179,8,0.5)] animate-bounce">
                    <Trophy size={48} className="text-white drop-shadow-md" />
                </div>

                <h2 className="text-3xl font-black text-transparent bg-clip-text bg-gradient-to-r from-neon-purple to-pink-500 mb-2 uppercase italic">
                    Check-In Complete!
                </h2>
                <p className="text-gray-300 mb-8 font-medium">
                    See you tomorrow, {currentUser.appUsername}!
                </p>

                <button
                    onClick={() => setShowReward(false)}
                    className="w-full py-3 bg-white text-black font-bold rounded-xl hover:scale-105 transition-transform shadow-lg"
                >
                    Awesome!
                </button>
            </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Trash2, Save, ArrowLeft, Plus, Settings, Database, Cloud, CloudOff, Download, Upload, ListMusic, Loader2, RefreshCw, Users, CheckCircle2, Clock, Music } from 'lucide-react';
import { TargetTrack, CloudConfig, User } from '../types';
import { storageService } from '../services/storage';
import { DEFAULT_CLOUD_CONFIG } from '../constants';

interface AdminPanelProps {
  tracks: TargetTrack[];
  spotifyId: string;
  onSave: (tracks: TargetTrack[]) => void;
  onSaveSpotify: (id: string) => void;
  onExit: () => void;
}

export const AdminPanel: React.FC<AdminPanelProps> = ({ tracks, spotifyId, onSave, onSaveSpotify, onExit }) => {
  const [activeTab, setActiveTab] = useState<'playlist' | 'users' | 'settings'>('playlist');

  // Playlist State
  const [localTracks, setLocalTracks] = useState<TargetTrack[]>(tracks);
  const [newArtist, setNewArtist] = useState('');
  const [newTitle, setNewTitle] = useState('');

  // Spotify State
  const [localSpotifyId, setLocalSpotifyId] = useState(spotifyId);
  const [spotifyInput, setSpotifyInput] = useState(`https://open.spotify.com/playlist/${spotifyId}`);

  // Users State
  const [usersList, setUsersList] = useState<User[]>([]);
  const [isLoadingUsers, setIsLoadingUsers] = useState(false);

  // Settings State
  const [cloudConfig, setCloudConfig] = useState<CloudConfig>({ enabled: false, binId: '', apiKey: '' });
  const [settingsMsg, setSettingsMsg] = useState<string | null>(null);
  const [isVerifying, setIsVerifying] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Check if defaults are actually present in the code
  const hasDefaults = !!(DEFAULT_CLOUD_CONFIG.binId && DEFAULT_CLOUD_CONFIG.apiKey);

  useEffect(() => {
    // Load existing cloud config when panel opens
    const config = storageService.getCloudConfig();
    if (config) {
      setCloudConfig(config);
    }
  }, []);

  // Fetch Users when switching to 'users' tab
  useEffect(() => {
    if (activeTab === 'users') {
        fetchUsers();
    }
  }, [activeTab]);

  const fetchUsers = async () => {
    setIsLoadingUsers(true);
    try {
        const fetchedUsers = await storageService.getUsers();
        setUsersList(fetchedUsers);
    } catch (e) {
        console.error("Failed to fetch users", e);
    } finally {
        setIsLoadingUsers(false);
    }
  };

  // --- PLAYLIST LOGIC ---
  const handleAddTrack = () => {
    if (!newArtist.trim() || !newTitle.trim()) return;
    const newTrack: TargetTrack = {
      id: Date.now().toString(),
      artist: newArtist.trim(),
      title: newTitle.trim(),
    };
    setLocalTracks([...localTracks, newTrack]);
    setNewArtist('');
    setNewTitle('');
  };

  const handleRemoveTrack = (id: string) => {
    setLocalTracks(localTracks.filter(t => t.id !== id));
  };

  const handleSavePlaylist = () => {
    onSave(localTracks);
  };

  const handleSpotifyChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    setSpotifyInput(val);

    // Extract ID from URL
    // Supports: https://open.spotify.com/playlist/37i9dQZF1DXcBWIGoYBM5M?si=...
    const match = val.match(/playlist\/([a-zA-Z0-9]+)/);
    if (match && match[1]) {
        setLocalSpotifyId(match[1]);
    } else if (!val.includes('http')) {
        // Assume user pasted just the ID
        setLocalSpotifyId(val);
    }
  };

  const handleSaveSpotify = () => {
      onSaveSpotify(localSpotifyId);
      alert('Spotify Playlist updated!');
  };

  // --- SETTINGS LOGIC ---
  const handleSaveCloudConfig = async () => {
    setSettingsMsg(null);
    if (!cloudConfig.binId || !cloudConfig.apiKey) {
        setSettingsMsg('Please enter both Bin ID and API Key.');
        return;
    }

    setIsVerifying(true);

    // Verify connection first
    const verification = await storageService.verifyConnection(cloudConfig.binId, cloudConfig.apiKey);

    setIsVerifying(false);

    if (verification.valid) {
      const newConfig = { ...cloudConfig, enabled: true };
      storageService.saveCloudConfig(newConfig);
      setCloudConfig(newConfig);
      setSettingsMsg('SUCCESS: Cloud Connected! Please reload the app.');
    } else {
      setSettingsMsg(`ERROR: ${verification.message}`);
    }
  };

  const handleDisconnectOrReset = () => {
    storageService.disconnectCloud(); // Clears LocalStorage

    if (hasDefaults) {
        // If defaults exist, revert UI to defaults
        setCloudConfig(DEFAULT_CLOUD_CONFIG);
        setSettingsMsg('Reset to Default Configuration.');
    } else {
        // If no defaults, clear UI completely
        setCloudConfig({ enabled: false, binId: '', apiKey: '' });
        setSettingsMsg('Cloud Disconnected. Using Local Storage.');
    }
  };

  const handleExportData = () => {
    try {
      const data = storageService.exportData();
      const backupData = {
        version: 1,
        timestamp: new Date().toISOString(),
        users: data.users ? JSON.parse(data.users) : [],
        playlist: data.tracks ? JSON.parse(data.tracks) : [],
      };
      const blob = new Blob([JSON.stringify(backupData, null, 2)], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `streamguard_admin_backup.json`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
      setSettingsMsg('Backup downloaded.');
    } catch (err) { setSettingsMsg('Failed to generate backup.'); }
  };

  const handleImportClick = () => { fileInputRef.current?.click(); };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        if (window.confirm('WARNING: This will overwrite ALL data (users & playlist). Continue?')) {
            storageService.importData(
              json.users ? JSON.stringify(json.users) : null,
              json.playlist ? JSON.stringify(json.playlist) : null
            );
            alert('Data restored successfully. Reloading...');
            window.location.reload();
        }
      } catch (err) { alert('Invalid backup file.'); }
    };
    reader.readAsText(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  // Helper to check if user checked in today
  const isCheckedInToday = (dateString: string | null) => {
    if (!dateString) return false;
    const today = new Date().toLocaleDateString();
    return dateString === today;
  };

  return (
    <div className="w-full max-w-4xl mx-auto p-4 md:p-6 animate-fade-in">
      <div className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-4">
        <h2 className="text-3xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-purple-400 to-pink-600">
          Admin Dashboard
        </h2>
        <button 
          onClick={onExit}
          className="flex items-center gap-2 px-4 py-2 rounded-lg bg-white/10 hover:bg-white/20 transition-all text-sm font-medium self-start md:self-auto"
        >
          <ArrowLeft size={16} />
          Exit Admin
        </button>
      </div>

      {/* Tabs */}
      <div className="flex gap-2 md:gap-4 mb-6 overflow-x-auto">
        <button 
            onClick={() => setActiveTab('playlist')}
            className={`flex-1 py-3 px-4 rounded-xl font-bold flex items-center justify-center gap-2 transition-all whitespace-nowrap ${activeTab === 'playlist' ? 'bg-purple-600 text-white shadow-lg shadow-purple-900/40' : 'bg-white/5 text-gray-400 hover:bg-white/10'}`}
        >
            <ListMusic size={18} /> Playlist
        </button>
        <button 
            onClick={() => setActiveTab('users')}
            className={`flex-1 py-3 px-4 rounded-xl font-bold flex items-center justify-center gap-2 transition-all whitespace-nowrap ${activeTab === 'users' ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-900/40' : 'bg-white/5 text-gray-400 hover:bg-white/10'}`}
        >
            <Users size={18} /> User Activity
        </button>
        <button 
            onClick={() => setActiveTab('settings')}
            className={`flex-1 py-3 px-4 rounded-xl font-bold flex items-center justify-center gap-2 transition-all whitespace-nowrap ${activeTab === 'settings' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/40' : 'bg-white/5 text-gray-400 hover:bg-white/10'}`}
        >
            <Settings size={18} /> Settings
        </button>
      </div>

      {activeTab === 'playlist' && (
        <>
            {/* Spotify Config */}
            <div className="glass p-6 rounded-2xl mb-8 border border-green-500/20 shadow-lg shadow-green-900/20">
                <h3 className="text-lg font-semibold text-green-400 mb-4 flex items-center gap-2">
                    <Music size={20} /> Spotify Integration
                </h3>
                <div className="flex flex-col md:flex-row gap-4">
                    <input 
                        type="text" 
                        placeholder="Paste Spotify Playlist Link (e.g. https://open.spotify.com/playlist/...)"
                        value={spotifyInput}
                        onChange={handleSpotifyChange}
                        className="flex-[2] bg-black/40 border border-white/10 rounded-xl px-4 py-3 focus:outline-none focus:border-green-500 transition-colors text-sm"
                    />
                    <button 
                        onClick={handleSaveSpotify}
                        className="bg-green-600 hover:bg-green-500 text-white rounded-xl px-6 py-3 font-bold transition-all flex items-center justify-center gap-2"
                    >
                        <Save size={18} /> Update Playlist
                    </button>
                </div>
                <p className="text-xs text-gray-500 mt-2">
                    This playlist will be embedded in the Member View for streaming.
                    Current ID: <span className="font-mono text-gray-400">{localSpotifyId}</span>
                </p>
            </div>

            {/* Add New Track Form */}
            <div className="glass p-6 rounded-2xl mb-8 shadow-lg shadow-purple-900/20">
                <h3 className="text-lg font-semibold text-purple-300 mb-4">Add Target Track</h3>
                <div className="flex flex-col md:flex-row gap-4">
                <input 
                    type="text" 
                    placeholder="Artist Name"
                    value={newArtist}
                    onChange={(e) => setNewArtist(e.target.value)}
                    className="flex-1 bg-black/40 border border-white/10 rounded-xl px-4 py-3 focus:outline-none focus:border-purple-500 transition-colors"
                />
                <input 
                    type="text" 
                    placeholder="Track Title"
                    value={newTitle}
                    onChange={(e) => setNewTitle(e.target.value)}
                    className="flex-1 bg-black/40 border border-white/10 rounded-xl px-4 py-3 focus:outline-none focus:border-purple-500 transition-colors"
                />
                <button 
                    onClick={handleAddTrack}
                    className="bg-purple-600 hover:bg-purple-500 text-white rounded-xl px-6 py-3 font-bold transition-all shadow-[0_0_15px_rgba(168,85,247,0.4)] flex items-center justify-center gap-2"
                >
                    <Plus size={20} />
                    Add
                </button>
                </div>
            </div>

            {/* Track List */}
            <div className="glass p-6 rounded-2xl shadow-lg shadow-purple-900/20">
                <div className="flex justify-between items-center mb-4">
                <h3 className="text-lg font-semibold text-purple-300">Current Playlist ({localTracks.length})</h3>
                <button 
                    onClick={handleSavePlaylist}
                    className="flex items-center gap-2 bg-green-500/80 hover:bg-green-500 text-white px-4 py-2 rounded-lg font-medium transition-all shadow-[0_0_15px_rgba(74,222,128,0.4)]"
                >
                    <Save size={18} />
                    Save Changes
                </button>
                </div>

                <div className="space-y-3">
                {localTracks.length === 0 ? (
                    <p className="text-center text-gray-400 py-8 italic">No tracks in the playlist.</p>
                ) : (
                    localTracks.map((track) => (
                    <div key={track.id} className="flex items-center justify-between p-4 bg-black/30 rounded-xl border border-white/5 hover:border-purple-500/30 transition-all">
                        <div>
                        <div className="font-bold text-white">{track.title}</div>
                        <div className="text-sm text-gray-400">{track.artist}</div>
                        </div>
                        <button 
                        onClick={() => handleRemoveTrack(track.id)}
                        className="text-red-400 hover:text-red-300 hover:bg-red-900/20 p-2 rounded-lg transition-colors"
                        >
                        <Trash2 size={20} />
                        </button>
                    </div>
                    ))
                )}
                </div>
            </div>
        </>
      )}

      {activeTab === 'users' && (
        <div className="glass p-6 rounded-2xl shadow-lg shadow-emerald-900/20 animate-fade-in">
           <div className="flex justify-between items-center mb-6">
                <div>
                    <h3 className="text-xl font-bold text-emerald-400 flex items-center gap-2">
                        <Users /> Community Activity
                    </h3>
                    <p className="text-sm text-gray-400">Monitor who has completed their daily check-in.</p>
                </div>
                <button 
                    onClick={fetchUsers} 
                    className="p-2 bg-white/5 hover:bg-white/10 rounded-lg transition-colors"
                    title="Refresh List"
                >
                    <RefreshCw size={20} className={isLoadingUsers ? 'animate-spin' : ''} />
                </button>
           </div>

           {isLoadingUsers ? (
               <div className="py-12 flex justify-center text-emerald-500">
                   <Loader2 className="animate-spin" size={32} />
               </div>
           ) : (
               <div className="overflow-x-auto">
                   <table className="w-full text-left border-collapse">
                       <thead>
                           <tr className="text-gray-400 border-b border-white/10 text-sm uppercase tracking-wider">
                               <th className="pb-3 pl-2">App User</th>
                               <th className="pb-3">Last.fm</th>
                               <th className="pb-3 text-center">Today's Status</th>
                               <th className="pb-3 text-right pr-2">Last Active</th>
                           </tr>
                       </thead>
                       <tbody className="divide-y divide-white/5">
                           {usersList.length === 0 ? (
                               <tr>
                                   <td colSpan={4} className="text-center py-8 text-gray-500 italic">
                                       No registered users found.
                                   </td>
                               </tr>
                           ) : (
                               usersList.map((user) => {
                                   const checkedIn = isCheckedInToday(user.lastCheckInDate);
                                   return (
                                       <tr key={user.id} className="group hover:bg-white/5 transition-colors">
                                           <td className={`py-4 pl-2 font-bold ${checkedIn ? 'text-white' : 'text-red-400'}`}>{user.appUsername}</td>
                                           <td className="py-4 text-gray-400 text-sm font-mono">{user.lastFmUsername}</td>
                                           <td className="py-4 flex justify-center">
                                               {checkedIn ? (
                                                   <div className="flex items-center gap-1 bg-green-900/30 text-green-400 px-3 py-1 rounded-full text-xs font-bold border border-green-500/20">
                                                       <CheckCircle2 size={14} /> Checked In
                                                   </div>
                                               ) : (
                                                   <div className="flex items-center gap-1 bg-red-900/20 text-red-400 px-3 py-1 rounded-full text-xs font-bold border border-red-500/30">
                                                        <Clock size={14} /> Not Checked In
                                                   </div>
                                               )}
                                           </td>
                                           <td className="py-4 text-right pr-2 text-sm text-gray-500">
                                               {user.lastCheckInDate || 'Never'}
                                           </td>
                                       </tr>
                                   );
                               })
                           )}
                       </tbody>
                   </table>
               </div>
           )}
        </div>
      )}

      {activeTab === 'settings' && (
        <div className="animate-fade-in space-y-6">

            {/* Cloud Config Section */}
            <div className="glass p-6 rounded-2xl border border-blue-500/20">
                <h3 className="text-xl font-bold mb-4 flex items-center gap-2 text-blue-400">
                    <Cloud /> Database Connection
                </h3>

                {/* Default Config Banner */}
                {hasDefaults && (
                    <div className="mb-6 p-4 bg-blue-900/20 border border-blue-400/30 rounded-xl flex items-center justify-between gap-3">
                        <div className="text-sm text-blue-200">
                            <strong>System Default Active:</strong> Using hardcoded connection keys.
                        </div>
                    </div>
                )}

                <p className="text-sm text-gray-400 mb-6">
                    Connect to JSONBin.io to allow users to sync data across different devices.
                </p>

                <div className="space-y-4">
                    <div>
                        <label className="text-xs font-bold text-gray-500 block mb-1">Bin ID</label>
                        <input 
                            type="text" 
                            value={cloudConfig.binId} 
                            onChange={(e) => setCloudConfig({...cloudConfig, binId: e.target.value})}
                            className="w-full bg-black/50 border border-white/10 rounded-lg p-3 text-white focus:border-blue-500 focus:outline-none font-mono"
                            placeholder="e.g. 65d4f..."
                        />
                    </div>
                    <div>
                        <label className="text-xs font-bold text-gray-500 block mb-1">Master Key (X-Master-Key)</label>
                        <input 
                            type="password" 
                            value={cloudConfig.apiKey} 
                            onChange={(e) => setCloudConfig({...cloudConfig, apiKey: e.target.value})}
                            className="w-full bg-black/50 border border-white/10 rounded-lg p-3 text-white focus:border-blue-500 focus:outline-none font-mono"
                            placeholder="e.g. $2a$10$..."
                        />
                    </div>

                    <div className="flex gap-4 pt-2">
                        <button 
                            onClick={handleSaveCloudConfig}
                            disabled={isVerifying}
                            className={`flex-1 py-3 rounded-xl font-bold text-white transition-colors flex items-center justify-center gap-2 ${isVerifying ? 'bg-blue-800' : 'bg-blue-600 hover:bg-blue-500'}`}
                        >
                            {isVerifying && <Loader2 className="animate-spin" size={18} />}
                            {cloudConfig.enabled ? 'Update Connection' : 'Connect Cloud'}
                        </button>

                        {cloudConfig.enabled && !isVerifying && (
                            <button 
                                onClick={handleDisconnectOrReset}
                                className={`px-6 py-3 rounded-xl font-bold transition-colors flex items-center gap-2 ${hasDefaults ? 'bg-yellow-600/50 text-yellow-200 hover:bg-yellow-600' : 'bg-red-900/50 text-red-300 hover:bg-red-900'}`}
                            >
                                {hasDefaults ? <RefreshCw size={18} /> : <CloudOff size={18} />}
                                {hasDefaults ? 'Reset to Default' : 'Disconnect'}
                            </button>
                        )}
                    </div>
                </div>
            </div>

            {/* Backup Section */}
            <div className="glass p-6 rounded-2xl border border-white/10">
                <h3 className="text-xl font-bold mb-4 flex items-center gap-2 text-white">
                    <Database /> Manual Backup
                </h3>
                <p className="text-sm text-gray-400 mb-6">
                    Download a local copy of the entire database (Users + Playlist) or restore from a file.
                </p>

                <div className="grid grid-cols-2 gap-4">
                    <button 
                        onClick={handleExportData}
                        className="py-4 bg-white/5 border border-white/10 hover:bg-white/10 rounded-xl flex flex-col items-center justify-center gap-2 transition-all"
                    >
                        <Download size={24} className="text-neon-green" /> 
                        <span className="font-bold">Backup to JSON</span>
                    </button>

                    <div className="relative">
                        <input type="file" ref={fileInputRef} onChange={handleFileChange} accept=".json" className="hidden" />
                        <button 
                            onClick={handleImportClick}
                            className="w-full h-full py-4 bg-white/5 border border-white/10 hover:bg-white/10 rounded-xl flex flex-col items-center justify-center gap-2 transition-all"
                        >
                            <Upload size={24} className="text-orange-400" /> 
                            <span className="font-bold">Restore from JSON</span>
                        </button>
                    </div>
                </div>
            </div>

            {settingsMsg && (
                <div className={`p-4 rounded-xl text-center font-medium border animate-pulse ${
                    settingsMsg.includes('SUCCESS') ? 'bg-green-900/20 border-green-500/30 text-green-300' : 
                    settingsMsg.includes('ERROR') ? 'bg-red-900/20 border-red-500/30 text-red-300' :
                    'bg-white/10 border-white/20 text-white'
                }`}>
                    {settingsMsg}
                </div>
            )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Trash2, Save, ArrowLeft, Plus, Settings, Database, Cloud, CloudOff, Download, Upload, ListMusic, Loader2, RefreshCw, Users, CheckCircle2, Clock, Music, Search, Filter, XCircle, BarChart3 } from 'lucide-react';
import { TargetTrack, CloudConfig, User } from '../types';
import { storageService } from '../services/storage';
import { DEFAULT_CLOUD_CONFIG } from '../constants';

interface AdminPanelProps {
  tracks: TargetTrack[];
  spotifyId: string;
  onSave: (tracks: TargetTrack[]) => void;
  onSaveSpotify: (id: string) => void;
  onExit: () => void;
}

export const AdminPanel: React.FC<AdminPanelProps> = ({ tracks, spotifyId, onSave, onSaveSpotify, onExit }) => {
  const [activeTab, setActiveTab] = useState<'playlist' | 'users' | 'settings'>('playlist');

  // Playlist State
  const [localTracks, setLocalTracks] = useState<TargetTrack[]>(tracks);
  const [newArtist, setNewArtist] = useState('');
  const [newTitle, setNewTitle] = useState('');

  // Spotify State
  const [localSpotifyId, setLocalSpotifyId] = useState(spotifyId);
  const [spotifyInput, setSpotifyInput] = useState(`https://open.spotify.com/playlist/${spotifyId}`);

  // Users State
  const [usersList, setUsersList] = useState<User[]>([]);
  const [isLoadingUsers, setIsLoadingUsers] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [filterStatus, setFilterStatus] = useState<'all' | 'checked' | 'missing'>('all');

  // Settings State
  const [cloudConfig, setCloudConfig] = useState<CloudConfig>({ enabled: false, binId: '', apiKey: '' });
  const [settingsMsg, setSettingsMsg] = useState<string | null>(null);
  const [isVerifying, setIsVerifying] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Check if defaults are actually present in the code
  const hasDefaults = !!(DEFAULT_CLOUD_CONFIG.binId && DEFAULT_CLOUD_CONFIG.apiKey);

  useEffect(() => {
    // Load existing cloud config when panel opens
    const config = storageService.getCloudConfig();
    if (config) {
      setCloudConfig(config);
    }
  }, []);

  // Fetch Users when switching to 'users' tab
  useEffect(() => {
    if (activeTab === 'users') {
        fetchUsers();
    }
  }, [activeTab]);

  const fetchUsers = async () => {
    setIsLoadingUsers(true);
    try {
        const fetchedUsers = await storageService.getUsers();
        setUsersList(fetchedUsers);
    } catch (e) {
        console.error("Failed to fetch users", e);
    } finally {
        setIsLoadingUsers(false);
    }
  };

  // --- PLAYLIST LOGIC ---
  const handleAddTrack = () => {
    if (!newArtist.trim() || !newTitle.trim()) return;
    const newTrack: TargetTrack = {
      id: Date.now().toString(),
      artist: newArtist.trim(),
      title: newTitle.trim(),
    };
    setLocalTracks([...localTracks, newTrack]);
    setNewArtist('');
    setNewTitle('');
  };

  const handleRemoveTrack = (id: string) => {
    setLocalTracks(localTracks.filter(t => t.id !== id));
  };

  const handleSavePlaylist = () => {
    onSave(localTracks);
  };

  const handleSpotifyChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    setSpotifyInput(val);

    // Extract ID from URL
    // Supports: https://open.spotify.com/playlist/37i9dQZF1DXcBWIGoYBM5M?si=...
    const match = val.match(/playlist\/([a-zA-Z0-9]+)/);
    if (match && match[1]) {
        setLocalSpotifyId(match[1]);
    } else if (!val.includes('http')) {
        // Assume user pasted just the ID
        setLocalSpotifyId(val);
    }
  };

  const handleSaveSpotify = () => {
      onSaveSpotify(localSpotifyId);
      alert('Spotify Playlist updated!');
  };

  // --- SETTINGS LOGIC ---
  const handleSaveCloudConfig = async () => {
    setSettingsMsg(null);
    if (!cloudConfig.binId || !cloudConfig.apiKey) {
        setSettingsMsg('Please enter both Bin ID and API Key.');
        return;
    }

    setIsVerifying(true);

    // Verify connection first
    const verification = await storageService.verifyConnection(cloudConfig.binId, cloudConfig.apiKey);

    setIsVerifying(false);

    if (verification.valid) {
      const newConfig = { ...cloudConfig, enabled: true };
      storageService.saveCloudConfig(newConfig);
      setCloudConfig(newConfig);
      setSettingsMsg('SUCCESS: Cloud Connected! Please reload the app.');
    } else {
      setSettingsMsg(`ERROR: ${verification.message}`);
    }
  };

  const handleDisconnectOrReset = () => {
    storageService.disconnectCloud(); // Clears LocalStorage

    if (hasDefaults) {
        // If defaults exist, revert UI to defaults
        setCloudConfig(DEFAULT_CLOUD_CONFIG);
        setSettingsMsg('Reset to Default Configuration.');
    } else {
        // If no defaults, clear UI completely
        setCloudConfig({ enabled: false, binId: '', apiKey: '' });
        setSettingsMsg('Cloud Disconnected. Using Local Storage.');
    }
  };

  const handleExportData = () => {
    try {
      const data = storageService.exportData();
      const backupData = {
        version: 1,
        timestamp: new Date().toISOString(),
        users: data.users ? JSON.parse(data.users) : [],
        playlist: data.tracks ? JSON.parse(data.tracks) : [],
      };
      const blob = new Blob([JSON.stringify(backupData, null, 2)], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `streamguard_admin_backup.json`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
      setSettingsMsg('Backup downloaded.');
    } catch (err) { setSettingsMsg('Failed to generate backup.'); }
  };

  const handleImportClick = () => { fileInputRef.current?.click(); };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        if (window.confirm('WARNING: This will overwrite ALL data (users & playlist). Continue?')) {
            storageService.importData(
              json.users ? JSON.stringify(json.users) : null,
              json.playlist ? JSON.stringify(json.playlist) : null
            );
            alert('Data restored successfully. Reloading...');
            window.location.reload();
        }
      } catch (err) { alert('Invalid backup file.'); }
    };
    reader.readAsText(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  // Helper to check if user checked in today
  const isCheckedInToday = (dateString: string | null) => {
    if (!dateString) return false;
    const today = new Date().toLocaleDateString();
    return dateString === today;
  };

  // --- FILTER & STATS LOGIC ---
  const getFilteredUsers = () => {
    return usersList.filter(user => {
      const matchesSearch = user.appUsername.toLowerCase().includes(searchQuery.toLowerCase()) || 
                            user.lastFmUsername.toLowerCase().includes(searchQuery.toLowerCase());

      const checkedIn = isCheckedInToday(user.lastCheckInDate);

      if (filterStatus === 'checked') return matchesSearch && checkedIn;
      if (filterStatus === 'missing') return matchesSearch && !checkedIn;

      return matchesSearch;
    });
  };

  const stats = {
    total: usersList.length,
    checkedIn: usersList.filter(u => isCheckedInToday(u.lastCheckInDate)).length,
    missing: 0 // calculated below
  };
  stats.missing = stats.total - stats.checkedIn;
  const completionRate = stats.total > 0 ? Math.round((stats.checkedIn / stats.total) * 100) : 0;

  const filteredUsers = getFilteredUsers();

  return (
    <div className="w-full max-w-4xl mx-auto p-4 md:p-6 animate-fade-in">
      <div className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-4">
        <h2 className="text-3xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-purple-400 to-pink-600">
          Admin Dashboard
        </h2>
        <button 
          onClick={onExit}
          className="flex items-center gap-2 px-4 py-2 rounded-lg bg-white/10 hover:bg-white/20 transition-all text-sm font-medium self-start md:self-auto"
        >
          <ArrowLeft size={16} />
          Exit Admin
        </button>
      </div>

      {/* Tabs */}
      <div className="flex gap-2 md:gap-4 mb-6 overflow-x-auto">
        <button 
            onClick={() => setActiveTab('playlist')}
            className={`flex-1 py-3 px-4 rounded-xl font-bold flex items-center justify-center gap-2 transition-all whitespace-nowrap ${activeTab === 'playlist' ? 'bg-purple-600 text-white shadow-lg shadow-purple-900/40' : 'bg-white/5 text-gray-400 hover:bg-white/10'}`}
        >
            <ListMusic size={18} /> Playlist
        </button>
        <button 
            onClick={() => setActiveTab('users')}
            className={`flex-1 py-3 px-4 rounded-xl font-bold flex items-center justify-center gap-2 transition-all whitespace-nowrap ${activeTab === 'users' ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-900/40' : 'bg-white/5 text-gray-400 hover:bg-white/10'}`}
        >
            <Users size={18} /> User Activity
        </button>
        <button 
            onClick={() => setActiveTab('settings')}
            className={`flex-1 py-3 px-4 rounded-xl font-bold flex items-center justify-center gap-2 transition-all whitespace-nowrap ${activeTab === 'settings' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/40' : 'bg-white/5 text-gray-400 hover:bg-white/10'}`}
        >
            <Settings size={18} /> Settings
        </button>
      </div>

      {activeTab === 'playlist' && (
        <>
            {/* Spotify Config */}
            <div className="glass p-6 rounded-2xl mb-8 border border-green-500/20 shadow-lg shadow-green-900/20">
                <h3 className="text-lg font-semibold text-green-400 mb-4 flex items-center gap-2">
                    <Music size={20} /> Spotify Integration
                </h3>
                <div className="flex flex-col md:flex-row gap-4">
                    <input 
                        type="text" 
                        placeholder="Paste Spotify Playlist Link (e.g. https://open.spotify.com/playlist/...)"
                        value={spotifyInput}
                        onChange={handleSpotifyChange}
                        className="flex-[2] bg-black/40 border border-white/10 rounded-xl px-4 py-3 focus:outline-none focus:border-green-500 transition-colors text-sm"
                    />
                    <button 
                        onClick={handleSaveSpotify}
                        className="bg-green-600 hover:bg-green-500 text-white rounded-xl px-6 py-3 font-bold transition-all flex items-center justify-center gap-2"
                    >
                        <Save size={18} /> Update Playlist
                    </button>
                </div>
                <p className="text-xs text-gray-500 mt-2">
                    This playlist will be embedded in the Member View for streaming.
                    Current ID: <span className="font-mono text-gray-400">{localSpotifyId}</span>
                </p>
            </div>

            {/* Add New Track Form */}
            <div className="glass p-6 rounded-2xl mb-8 shadow-lg shadow-purple-900/20">
                <h3 className="text-lg font-semibold text-purple-300 mb-4">Add Target Track</h3>
                <div className="flex flex-col md:flex-row gap-4">
                <input 
                    type="text" 
                    placeholder="Artist Name"
                    value={newArtist}
                    onChange={(e) => setNewArtist(e.target.value)}
                    className="flex-1 bg-black/40 border border-white/10 rounded-xl px-4 py-3 focus:outline-none focus:border-purple-500 transition-colors"
                />
                <input 
                    type="text" 
                    placeholder="Track Title"
                    value={newTitle}
                    onChange={(e) => setNewTitle(e.target.value)}
                    className="flex-1 bg-black/40 border border-white/10 rounded-xl px-4 py-3 focus:outline-none focus:border-purple-500 transition-colors"
                />
                <button 
                    onClick={handleAddTrack}
                    className="bg-purple-600 hover:bg-purple-500 text-white rounded-xl px-6 py-3 font-bold transition-all shadow-[0_0_15px_rgba(168,85,247,0.4)] flex items-center justify-center gap-2"
                >
                    <Plus size={20} />
                    Add
                </button>
                </div>
            </div>

            {/* Track List */}
            <div className="glass p-6 rounded-2xl shadow-lg shadow-purple-900/20">
                <div className="flex justify-between items-center mb-4">
                <h3 className="text-lg font-semibold text-purple-300">Current Playlist ({localTracks.length})</h3>
                <button 
                    onClick={handleSavePlaylist}
                    className="flex items-center gap-2 bg-green-500/80 hover:bg-green-500 text-white px-4 py-2 rounded-lg font-medium transition-all shadow-[0_0_15px_rgba(74,222,128,0.4)]"
                >
                    <Save size={18} />
                    Save Changes
                </button>
                </div>

                <div className="space-y-3">
                {localTracks.length === 0 ? (
                    <p className="text-center text-gray-400 py-8 italic">No tracks in the playlist.</p>
                ) : (
                    localTracks.map((track) => (
                    <div key={track.id} className="flex items-center justify-between p-4 bg-black/30 rounded-xl border border-white/5 hover:border-purple-500/30 transition-all">
                        <div>
                        <div className="font-bold text-white">{track.title}</div>
                        <div className="text-sm text-gray-400">{track.artist}</div>
                        </div>
                        <button 
                        onClick={() => handleRemoveTrack(track.id)}
                        className="text-red-400 hover:text-red-300 hover:bg-red-900/20 p-2 rounded-lg transition-colors"
                        >
                        <Trash2 size={20} />
                        </button>
                    </div>
                    ))
                )}
                </div>
            </div>
        </>
      )}

      {activeTab === 'users' && (
        <div className="space-y-6 animate-fade-in">
           {/* Summary Stats Cards */}
           <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
               <div className="glass p-4 rounded-xl flex flex-col items-center justify-center border border-white/10">
                   <div className="text-gray-400 text-xs font-bold uppercase mb-1">Total Users</div>
                   <div className="text-2xl font-bold text-white">{stats.total}</div>
               </div>
               <div className="glass p-4 rounded-xl flex flex-col items-center justify-center border border-green-500/20 bg-green-900/10">
                   <div className="text-green-400 text-xs font-bold uppercase mb-1">Checked In</div>
                   <div className="text-2xl font-bold text-green-400">{stats.checkedIn}</div>
               </div>
               <div className="glass p-4 rounded-xl flex flex-col items-center justify-center border border-red-500/20 bg-red-900/10">
                   <div className="text-red-400 text-xs font-bold uppercase mb-1">Missing</div>
                   <div className="text-2xl font-bold text-red-400">{stats.missing}</div>
               </div>
               <div className="glass p-4 rounded-xl flex flex-col items-center justify-center border border-blue-500/20">
                   <div className="text-blue-400 text-xs font-bold uppercase mb-1">Completion</div>
                   <div className="text-2xl font-bold text-blue-400">{completionRate}%</div>
               </div>
           </div>

           <div className="glass p-6 rounded-2xl shadow-lg shadow-emerald-900/20">
                <div className="flex flex-col md:flex-row justify-between items-center mb-6 gap-4">
                    <div>
                        <h3 className="text-xl font-bold text-emerald-400 flex items-center gap-2">
                            <Users /> Community Activity
                        </h3>
                    </div>
                    <div className="flex gap-2 w-full md:w-auto">
                        <button 
                            onClick={fetchUsers} 
                            className="p-3 bg-white/5 hover:bg-white/10 rounded-xl transition-colors"
                            title="Refresh List"
                        >
                            <RefreshCw size={20} className={isLoadingUsers ? 'animate-spin' : ''} />
                        </button>
                    </div>
                </div>

                {/* Search and Filters Bar */}
                <div className="flex flex-col md:flex-row gap-3 mb-6">
                    <div className="flex-1 relative">
                        <Search className="absolute left-3 top-3 text-gray-500" size={18} />
                        <input 
                            type="text" 
                            placeholder="Search by username..." 
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            className="w-full bg-black/40 border border-white/10 rounded-xl pl-10 pr-4 py-2.5 focus:outline-none focus:border-emerald-500 text-white placeholder-gray-600 transition-colors"
                        />
                    </div>
                    <div className="flex bg-black/40 rounded-xl p-1 border border-white/10">
                        <button 
                            onClick={() => setFilterStatus('all')}
                            className={`px-4 py-1.5 rounded-lg text-sm font-bold transition-all ${filterStatus === 'all' ? 'bg-gray-700 text-white' : 'text-gray-400 hover:text-white'}`}
                        >
                            All
                        </button>
                        <button 
                            onClick={() => setFilterStatus('checked')}
                            className={`px-4 py-1.5 rounded-lg text-sm font-bold transition-all ${filterStatus === 'checked' ? 'bg-green-600 text-white' : 'text-gray-400 hover:text-green-400'}`}
                        >
                            Checked
                        </button>
                        <button 
                            onClick={() => setFilterStatus('missing')}
                            className={`px-4 py-1.5 rounded-lg text-sm font-bold transition-all ${filterStatus === 'missing' ? 'bg-red-600 text-white' : 'text-gray-400 hover:text-red-400'}`}
                        >
                            Missing
                        </button>
                    </div>
                </div>

                {isLoadingUsers ? (
                    <div className="py-12 flex justify-center text-emerald-500">
                        <Loader2 className="animate-spin" size={32} />
                    </div>
                ) : (
                    <div className="overflow-x-auto max-h-[600px] overflow-y-auto pr-2 custom-scrollbar">
                        <table className="w-full text-left border-collapse">
                            <thead className="sticky top-0 bg-[#16133a] z-10 shadow-sm">
                                <tr className="text-gray-400 border-b border-white/10 text-sm uppercase tracking-wider">
                                    <th className="pb-3 pl-2 pt-2">App User</th>
                                    <th className="pb-3 pt-2">Last.fm</th>
                                    <th className="pb-3 text-center pt-2">Status</th>
                                    <th className="pb-3 text-right pr-2 pt-2">Last Active</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-white/5">
                                {filteredUsers.length === 0 ? (
                                    <tr>
                                        <td colSpan={4} className="text-center py-8 text-gray-500 italic">
                                            {searchQuery ? 'No users match your search.' : 'No users found.'}
                                        </td>
                                    </tr>
                                ) : (
                                    filteredUsers.map((user) => {
                                        const checkedIn = isCheckedInToday(user.lastCheckInDate);
                                        return (
                                            <tr key={user.id} className="group hover:bg-white/5 transition-colors">
                                                <td className={`py-4 pl-2 font-bold ${checkedIn ? 'text-white' : 'text-red-400'}`}>
                                                    {user.appUsername}
                                                </td>
                                                <td className="py-4 text-gray-400 text-sm font-mono">{user.lastFmUsername}</td>
                                                <td className="py-4 flex justify-center">
                                                    {checkedIn ? (
                                                        <div className="flex items-center gap-1 bg-green-900/30 text-green-400 px-3 py-1 rounded-full text-xs font-bold border border-green-500/20">
                                                            <CheckCircle2 size={14} /> Checked In
                                                        </div>
                                                    ) : (
                                                        <div className="flex items-center gap-1 bg-red-900/20 text-red-400 px-3 py-1 rounded-full text-xs font-bold border border-red-500/30">
                                                                <XCircle size={14} /> Missing
                                                        </div>
                                                    )}
                                                </td>
                                                <td className="py-4 text-right pr-2 text-sm text-gray-500">
                                                    {user.lastCheckInDate || 'Never'}
                                                </td>
                                            </tr>
                                        );
                                    })
                                )}
                            </tbody>
                        </table>
                    </div>
                )}
           </div>
        </div>
      )}

      {activeTab === 'settings' && (
        <div className="animate-fade-in space-y-6">

            {/* Cloud Config Section */}
            <div className="glass p-6 rounded-2xl border border-blue-500/20">
                <h3 className="text-xl font-bold mb-4 flex items-center gap-2 text-blue-400">
                    <Cloud /> Database Connection
                </h3>

                {/* Default Config Banner */}
                {hasDefaults && (
                    <div className="mb-6 p-4 bg-blue-900/20 border border-blue-400/30 rounded-xl flex items-center justify-between gap-3">
                        <div className="text-sm text-blue-200">
                            <strong>System Default Active:</strong> Using hardcoded connection keys.
                        </div>
                    </div>
                )}

                <p className="text-sm text-gray-400 mb-6">
                    Connect to JSONBin.io to allow users to sync data across different devices.
                </p>

                <div className="space-y-4">
                    <div>
                        <label className="text-xs font-bold text-gray-500 block mb-1">Bin ID</label>
                        <input 
                            type="text" 
                            value={cloudConfig.binId} 
                            onChange={(e) => setCloudConfig({...cloudConfig, binId: e.target.value})}
                            className="w-full bg-black/50 border border-white/10 rounded-lg p-3 text-white focus:border-blue-500 focus:outline-none font-mono"
                            placeholder="e.g. 65d4f..."
                        />
                    </div>
                    <div>
                        <label className="text-xs font-bold text-gray-500 block mb-1">Master Key (X-Master-Key)</label>
                        <input 
                            type="password" 
                            value={cloudConfig.apiKey} 
                            onChange={(e) => setCloudConfig({...cloudConfig, apiKey: e.target.value})}
                            className="w-full bg-black/50 border border-white/10 rounded-lg p-3 text-white focus:border-blue-500 focus:outline-none font-mono"
                            placeholder="e.g. $2a$10$..."
                        />
                    </div>

                    <div className="flex gap-4 pt-2">
                        <button 
                            onClick={handleSaveCloudConfig}
                            disabled={isVerifying}
                            className={`flex-1 py-3 rounded-xl font-bold text-white transition-colors flex items-center justify-center gap-2 ${isVerifying ? 'bg-blue-800' : 'bg-blue-600 hover:bg-blue-500'}`}
                        >
                            {isVerifying && <Loader2 className="animate-spin" size={18} />}
                            {cloudConfig.enabled ? 'Update Connection' : 'Connect Cloud'}
                        </button>

                        {cloudConfig.enabled && !isVerifying && (
                            <button 
                                onClick={handleDisconnectOrReset}
                                className={`px-6 py-3 rounded-xl font-bold transition-colors flex items-center gap-2 ${hasDefaults ? 'bg-yellow-600/50 text-yellow-200 hover:bg-yellow-600' : 'bg-red-900/50 text-red-300 hover:bg-red-900'}`}
                            >
                                {hasDefaults ? <RefreshCw size={18} /> : <CloudOff size={18} />}
                                {hasDefaults ? 'Reset to Default' : 'Disconnect'}
                            </button>
                        )}
                    </div>
                </div>
            </div>

            {/* Backup Section */}
            <div className="glass p-6 rounded-2xl border border-white/10">
                <h3 className="text-xl font-bold mb-4 flex items-center gap-2 text-white">
                    <Database /> Manual Backup
                </h3>
                <p className="text-sm text-gray-400 mb-6">
                    Download a local copy of the entire database (Users + Playlist) or restore from a file.
                </p>

                <div className="grid grid-cols-2 gap-4">
                    <button 
                        onClick={handleExportData}
                        className="py-4 bg-white/5 border border-white/10 hover:bg-white/10 rounded-xl flex flex-col items-center justify-center gap-2 transition-all"
                    >
                        <Download size={24} className="text-neon-green" /> 
                        <span className="font-bold">Backup to JSON</span>
                    </button>

                    <div className="relative">
                        <input type="file" ref={fileInputRef} onChange={handleFileChange} accept=".json" className="hidden" />
                        <button 
                            onClick={handleImportClick}
                            className="w-full h-full py-4 bg-white/5 border border-white/10 hover:bg-white/10 rounded-xl flex flex-col items-center justify-center gap-2 transition-all"
                        >
                            <Upload size={24} className="text-orange-400" /> 
                            <span className="font-bold">Restore from JSON</span>
                        </button>
                    </div>
                </div>
            </div>

            {settingsMsg && (
                <div className={`p-4 rounded-xl text-center font-medium border animate-pulse ${
                    settingsMsg.includes('SUCCESS') ? 'bg-green-900/20 border-green-500/30 text-green-300' : 
                    settingsMsg.includes('ERROR') ? 'bg-red-900/20 border-red-500/30 text-red-300' :
                    'bg-white/10 border-white/20 text-white'
                }`}>
                    {settingsMsg}
                </div>
            )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Trash2, Save, ArrowLeft, Plus, Settings, Database, Cloud, CloudOff, Download, Upload, ListMusic, Loader2, RefreshCw, Users, CheckCircle2, Clock, Music, Search, Filter, XCircle, BarChart3, Calendar } from 'lucide-react';
import { TargetTrack, CloudConfig, User } from '../types';
import { storageService } from '../services/storage';
import { DEFAULT_CLOUD_CONFIG } from '../constants';

interface AdminPanelProps {
  tracks: TargetTrack[];
  spotifyId: string;
  onSave: (tracks: TargetTrack[]) => void;
  onSaveSpotify: (id: string) => void;
  onExit: () => void;
}

export const AdminPanel: React.FC<AdminPanelProps> = ({ tracks, spotifyId, onSave, onSaveSpotify, onExit }) => {
  const [activeTab, setActiveTab] = useState<'playlist' | 'users' | 'settings'>('playlist');

  // Playlist State
  const [localTracks, setLocalTracks] = useState<TargetTrack[]>(tracks);
  const [newArtist, setNewArtist] = useState('');
  const [newTitle, setNewTitle] = useState('');

  // Spotify State
  const [localSpotifyId, setLocalSpotifyId] = useState(spotifyId);
  const [spotifyInput, setSpotifyInput] = useState(`https://open.spotify.com/playlist/${spotifyId}`);

  // Users State
  const [usersList, setUsersList] = useState<User[]>([]);
  const [isLoadingUsers, setIsLoadingUsers] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [filterStatus, setFilterStatus] = useState<'all' | 'checked' | 'missing'>('all');

  // Settings State
  const [cloudConfig, setCloudConfig] = useState<CloudConfig>({ enabled: false, binId: '', apiKey: '' });
  const [settingsMsg, setSettingsMsg] = useState<string | null>(null);
  const [isVerifying, setIsVerifying] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Check if defaults are actually present in the code
  const hasDefaults = !!(DEFAULT_CLOUD_CONFIG.binId && DEFAULT_CLOUD_CONFIG.apiKey);

  useEffect(() => {
    // Load existing cloud config when panel opens
    const config = storageService.getCloudConfig();
    if (config) {
      setCloudConfig(config);
    }
  }, []);

  // Fetch Users when switching to 'users' tab
  useEffect(() => {
    if (activeTab === 'users') {
        fetchUsers();
    }
  }, [activeTab]);

  const fetchUsers = async () => {
    setIsLoadingUsers(true);
    try {
        const fetchedUsers = await storageService.getUsers();
        setUsersList(fetchedUsers);
    } catch (e) {
        console.error("Failed to fetch users", e);
    } finally {
        setIsLoadingUsers(false);
    }
  };

  // --- PLAYLIST LOGIC ---
  const handleAddTrack = () => {
    if (!newArtist.trim() || !newTitle.trim()) return;
    const newTrack: TargetTrack = {
      id: Date.now().toString(),
      artist: newArtist.trim(),
      title: newTitle.trim(),
    };
    setLocalTracks([...localTracks, newTrack]);
    setNewArtist('');
    setNewTitle('');
  };

  const handleRemoveTrack = (id: string) => {
    setLocalTracks(localTracks.filter(t => t.id !== id));
  };

  const handleSavePlaylist = () => {
    onSave(localTracks);
  };

  const handleSpotifyChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    setSpotifyInput(val);

    // Extract ID from URL
    // Supports: https://open.spotify.com/playlist/37i9dQZF1DXcBWIGoYBM5M?si=...
    const match = val.match(/playlist\/([a-zA-Z0-9]+)/);
    if (match && match[1]) {
        setLocalSpotifyId(match[1]);
    } else if (!val.includes('http')) {
        // Assume user pasted just the ID
        setLocalSpotifyId(val);
    }
  };

  const handleSaveSpotify = () => {
      onSaveSpotify(localSpotifyId);
      alert('Spotify Playlist updated!');
  };

  // --- SETTINGS LOGIC ---
  const handleSaveCloudConfig = async () => {
    setSettingsMsg(null);
    if (!cloudConfig.binId || !cloudConfig.apiKey) {
        setSettingsMsg('Please enter both Bin ID and API Key.');
        return;
    }

    setIsVerifying(true);

    // Verify connection first
    const verification = await storageService.verifyConnection(cloudConfig.binId, cloudConfig.apiKey);

    setIsVerifying(false);

    if (verification.valid) {
      const newConfig = { ...cloudConfig, enabled: true };
      storageService.saveCloudConfig(newConfig);
      setCloudConfig(newConfig);
      setSettingsMsg('SUCCESS: Cloud Connected! Please reload the app.');
    } else {
      setSettingsMsg(`ERROR: ${verification.message}`);
    }
  };

  const handleDisconnectOrReset = () => {
    storageService.disconnectCloud(); // Clears LocalStorage

    if (hasDefaults) {
        // If defaults exist, revert UI to defaults
        setCloudConfig(DEFAULT_CLOUD_CONFIG);
        setSettingsMsg('Reset to Default Configuration.');
    } else {
        // If no defaults, clear UI completely
        setCloudConfig({ enabled: false, binId: '', apiKey: '' });
        setSettingsMsg('Cloud Disconnected. Using Local Storage.');
    }
  };

  const handleExportData = () => {
    try {
      const data = storageService.exportData();
      const backupData = {
        version: 1,
        timestamp: new Date().toISOString(),
        users: data.users ? JSON.parse(data.users) : [],
        playlist: data.tracks ? JSON.parse(data.tracks) : [],
      };
      const blob = new Blob([JSON.stringify(backupData, null, 2)], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `streamguard_admin_backup.json`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
      setSettingsMsg('Backup downloaded.');
    } catch (err) { setSettingsMsg('Failed to generate backup.'); }
  };

  const handleImportClick = () => { fileInputRef.current?.click(); };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        if (window.confirm('WARNING: This will overwrite ALL data (users & playlist). Continue?')) {
            storageService.importData(
              json.users ? JSON.stringify(json.users) : null,
              json.playlist ? JSON.stringify(json.playlist) : null
            );
            alert('Data restored successfully. Reloading...');
            window.location.reload();
        }
      } catch (err) { alert('Invalid backup file.'); }
    };
    reader.readAsText(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  // Helper to check if user checked in today
  const isCheckedInToday = (dateString: string | null) => {
    if (!dateString) return false;
    const today = new Date().toLocaleDateString();
    return dateString === today;
  };

  // --- FILTER & STATS LOGIC ---
  const getFilteredUsers = () => {
    return usersList.filter(user => {
      const matchesSearch = user.appUsername.toLowerCase().includes(searchQuery.toLowerCase()) || 
                            user.lastFmUsername.toLowerCase().includes(searchQuery.toLowerCase());

      const checkedIn = isCheckedInToday(user.lastCheckInDate);

      if (filterStatus === 'checked') return matchesSearch && checkedIn;
      if (filterStatus === 'missing') return matchesSearch && !checkedIn;

      return matchesSearch;
    });
  };

  const stats = {
    total: usersList.length,
    checkedIn: usersList.filter(u => isCheckedInToday(u.lastCheckInDate)).length,
    missing: 0 // calculated below
  };
  stats.missing = stats.total - stats.checkedIn;
  const completionRate = stats.total > 0 ? Math.round((stats.checkedIn / stats.total) * 100) : 0;

  const filteredUsers = getFilteredUsers();

  // Display date for Admin clarity
  const todayDateDisplay = new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'short', day: 'numeric' });

  return (
    <div className="w-full max-w-4xl mx-auto p-4 md:p-6 animate-fade-in">
      <div className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-4">
        <h2 className="text-3xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-purple-400 to-pink-600">
          Admin Dashboard
        </h2>
        <button 
          onClick={onExit}
          className="flex items-center gap-2 px-4 py-2 rounded-lg bg-white/10 hover:bg-white/20 transition-all text-sm font-medium self-start md:self-auto"
        >
          <ArrowLeft size={16} />
          Exit Admin
        </button>
      </div>

      {/* Tabs */}
      <div className="flex gap-2 md:gap-4 mb-6 overflow-x-auto">
        <button 
            onClick={() => setActiveTab('playlist')}
            className={`flex-1 py-3 px-4 rounded-xl font-bold flex items-center justify-center gap-2 transition-all whitespace-nowrap ${activeTab === 'playlist' ? 'bg-purple-600 text-white shadow-lg shadow-purple-900/40' : 'bg-white/5 text-gray-400 hover:bg-white/10'}`}
        >
            <ListMusic size={18} /> Playlist
        </button>
        <button 
            onClick={() => setActiveTab('users')}
            className={`flex-1 py-3 px-4 rounded-xl font-bold flex items-center justify-center gap-2 transition-all whitespace-nowrap ${activeTab === 'users' ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-900/40' : 'bg-white/5 text-gray-400 hover:bg-white/10'}`}
        >
            <Users size={18} /> User Activity
        </button>
        <button 
            onClick={() => setActiveTab('settings')}
            className={`flex-1 py-3 px-4 rounded-xl font-bold flex items-center justify-center gap-2 transition-all whitespace-nowrap ${activeTab === 'settings' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/40' : 'bg-white/5 text-gray-400 hover:bg-white/10'}`}
        >
            <Settings size={18} /> Settings
        </button>
      </div>

      {activeTab === 'playlist' && (
        <>
            {/* Spotify Config */}
            <div className="glass p-6 rounded-2xl mb-8 border border-green-500/20 shadow-lg shadow-green-900/20">
                <h3 className="text-lg font-semibold text-green-400 mb-4 flex items-center gap-2">
                    <Music size={20} /> Spotify Integration
                </h3>
                <div className="flex flex-col md:flex-row gap-4">
                    <input 
                        type="text" 
                        placeholder="Paste Spotify Playlist Link (e.g. https://open.spotify.com/playlist/...)"
                        value={spotifyInput}
                        onChange={handleSpotifyChange}
                        className="flex-[2] bg-black/40 border border-white/10 rounded-xl px-4 py-3 focus:outline-none focus:border-green-500 transition-colors text-sm"
                    />
                    <button 
                        onClick={handleSaveSpotify}
                        className="bg-green-600 hover:bg-green-500 text-white rounded-xl px-6 py-3 font-bold transition-all flex items-center justify-center gap-2"
                    >
                        <Save size={18} /> Update Playlist
                    </button>
                </div>
                <p className="text-xs text-gray-500 mt-2">
                    This playlist will be embedded in the Member View for streaming.
                    Current ID: <span className="font-mono text-gray-400">{localSpotifyId}</span>
                </p>
            </div>

            {/* Add New Track Form */}
            <div className="glass p-6 rounded-2xl mb-8 shadow-lg shadow-purple-900/20">
                <h3 className="text-lg font-semibold text-purple-300 mb-4">Add Target Track</h3>
                <div className="flex flex-col md:flex-row gap-4">
                <input 
                    type="text" 
                    placeholder="Artist Name"
                    value={newArtist}
                    onChange={(e) => setNewArtist(e.target.value)}
                    className="flex-1 bg-black/40 border border-white/10 rounded-xl px-4 py-3 focus:outline-none focus:border-purple-500 transition-colors"
                />
                <input 
                    type="text" 
                    placeholder="Track Title"
                    value={newTitle}
                    onChange={(e) => setNewTitle(e.target.value)}
                    className="flex-1 bg-black/40 border border-white/10 rounded-xl px-4 py-3 focus:outline-none focus:border-purple-500 transition-colors"
                />
                <button 
                    onClick={handleAddTrack}
                    className="bg-purple-600 hover:bg-purple-500 text-white rounded-xl px-6 py-3 font-bold transition-all shadow-[0_0_15px_rgba(168,85,247,0.4)] flex items-center justify-center gap-2"
                >
                    <Plus size={20} />
                    Add
                </button>
                </div>
            </div>

            {/* Track List */}
            <div className="glass p-6 rounded-2xl shadow-lg shadow-purple-900/20">
                <div className="flex justify-between items-center mb-4">
                <h3 className="text-lg font-semibold text-purple-300">Current Playlist ({localTracks.length})</h3>
                <button 
                    onClick={handleSavePlaylist}
                    className="flex items-center gap-2 bg-green-500/80 hover:bg-green-500 text-white px-4 py-2 rounded-lg font-medium transition-all shadow-[0_0_15px_rgba(74,222,128,0.4)]"
                >
                    <Save size={18} />
                    Save Changes
                </button>
                </div>

                <div className="space-y-3">
                {localTracks.length === 0 ? (
                    <p className="text-center text-gray-400 py-8 italic">No tracks in the playlist.</p>
                ) : (
                    localTracks.map((track) => (
                    <div key={track.id} className="flex items-center justify-between p-4 bg-black/30 rounded-xl border border-white/5 hover:border-purple-500/30 transition-all">
                        <div>
                        <div className="font-bold text-white">{track.title}</div>
                        <div className="text-sm text-gray-400">{track.artist}</div>
                        </div>
                        <button 
                        onClick={() => handleRemoveTrack(track.id)}
                        className="text-red-400 hover:text-red-300 hover:bg-red-900/20 p-2 rounded-lg transition-colors"
                        >
                        <Trash2 size={20} />
                        </button>
                    </div>
                    ))
                )}
                </div>
            </div>
        </>
      )}

      {activeTab === 'users' && (
        <div className="space-y-6 animate-fade-in">
           {/* Summary Stats Cards */}
           <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
               <div className="glass p-4 rounded-xl flex flex-col items-center justify-center border border-white/10">
                   <div className="text-gray-400 text-xs font-bold uppercase mb-1">Total Users</div>
                   <div className="text-2xl font-bold text-white">{stats.total}</div>
               </div>
               <div className="glass p-4 rounded-xl flex flex-col items-center justify-center border border-green-500/20 bg-green-900/10">
                   <div className="text-green-400 text-xs font-bold uppercase mb-1">Checked In (Today)</div>
                   <div className="text-2xl font-bold text-green-400">{stats.checkedIn}</div>
               </div>
               <div className="glass p-4 rounded-xl flex flex-col items-center justify-center border border-red-500/20 bg-red-900/10">
                   <div className="text-red-400 text-xs font-bold uppercase mb-1">Missing (Today)</div>
                   <div className="text-2xl font-bold text-red-400">{stats.missing}</div>
               </div>
               <div className="glass p-4 rounded-xl flex flex-col items-center justify-center border border-blue-500/20">
                   <div className="text-blue-400 text-xs font-bold uppercase mb-1">Completion</div>
                   <div className="text-2xl font-bold text-blue-400">{completionRate}%</div>
               </div>
           </div>

           <div className="glass p-6 rounded-2xl shadow-lg shadow-emerald-900/20">
                <div className="flex flex-col md:flex-row justify-between items-center mb-6 gap-4">
                    <div>
                        <h3 className="text-xl font-bold text-emerald-400 flex items-center gap-2">
                            <Users /> Community Activity
                            <span className="text-sm font-normal text-gray-400 ml-2 border-l border-white/20 pl-3 flex items-center gap-1">
                                <Calendar size={14} /> {todayDateDisplay}
                            </span>
                        </h3>
                    </div>
                    <div className="flex gap-2 w-full md:w-auto">
                        <button 
                            onClick={fetchUsers} 
                            className="p-3 bg-white/5 hover:bg-white/10 rounded-xl transition-colors"
                            title="Refresh List"
                        >
                            <RefreshCw size={20} className={isLoadingUsers ? 'animate-spin' : ''} />
                        </button>
                    </div>
                </div>

                {/* Search and Filters Bar */}
                <div className="flex flex-col md:flex-row gap-3 mb-6">
                    <div className="flex-1 relative">
                        <Search className="absolute left-3 top-3 text-gray-500" size={18} />
                        <input 
                            type="text" 
                            placeholder="Search by username..." 
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            className="w-full bg-black/40 border border-white/10 rounded-xl pl-10 pr-4 py-2.5 focus:outline-none focus:border-emerald-500 text-white placeholder-gray-600 transition-colors"
                        />
                    </div>
                    <div className="flex bg-black/40 rounded-xl p-1 border border-white/10">
                        <button 
                            onClick={() => setFilterStatus('all')}
                            className={`px-4 py-1.5 rounded-lg text-sm font-bold transition-all ${filterStatus === 'all' ? 'bg-gray-700 text-white' : 'text-gray-400 hover:text-white'}`}
                        >
                            All
                        </button>
                        <button 
                            onClick={() => setFilterStatus('checked')}
                            className={`px-4 py-1.5 rounded-lg text-sm font-bold transition-all ${filterStatus === 'checked' ? 'bg-green-600 text-white' : 'text-gray-400 hover:text-green-400'}`}
                        >
                            Checked
                        </button>
                        <button 
                            onClick={() => setFilterStatus('missing')}
                            className={`px-4 py-1.5 rounded-lg text-sm font-bold transition-all ${filterStatus === 'missing' ? 'bg-red-600 text-white' : 'text-gray-400 hover:text-red-400'}`}
                        >
                            Missing
                        </button>
                    </div>
                </div>

                {isLoadingUsers ? (
                    <div className="py-12 flex justify-center text-emerald-500">
                        <Loader2 className="animate-spin" size={32} />
                    </div>
                ) : (
                    <div className="overflow-x-auto max-h-[600px] overflow-y-auto pr-2 custom-scrollbar">
                        <table className="w-full text-left border-collapse">
                            <thead className="sticky top-0 bg-[#16133a] z-10 shadow-sm">
                                <tr className="text-gray-400 border-b border-white/10 text-sm uppercase tracking-wider">
                                    <th className="pb-3 pl-2 pt-2">App User</th>
                                    <th className="pb-3 pt-2">Last.fm</th>
                                    <th className="pb-3 text-center pt-2">Status</th>
                                    <th className="pb-3 text-right pr-2 pt-2">Last Active</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-white/5">
                                {filteredUsers.length === 0 ? (
                                    <tr>
                                        <td colSpan={4} className="text-center py-8 text-gray-500 italic">
                                            {searchQuery ? 'No users match your search.' : 'No users found.'}
                                        </td>
                                    </tr>
                                ) : (
                                    filteredUsers.map((user) => {
                                        const checkedIn = isCheckedInToday(user.lastCheckInDate);
                                        return (
                                            <tr key={user.id} className="group hover:bg-white/5 transition-colors">
                                                <td className={`py-4 pl-2 font-bold ${checkedIn ? 'text-white' : 'text-red-400'}`}>
                                                    {user.appUsername}
                                                </td>
                                                <td className="py-4 text-gray-400 text-sm font-mono">{user.lastFmUsername}</td>
                                                <td className="py-4 flex justify-center">
                                                    {checkedIn ? (
                                                        <div className="flex items-center gap-1 bg-green-900/30 text-green-400 px-3 py-1 rounded-full text-xs font-bold border border-green-500/20">
                                                            <CheckCircle2 size={14} /> Checked In
                                                        </div>
                                                    ) : (
                                                        <div className="flex items-center gap-1 bg-red-900/20 text-red-400 px-3 py-1 rounded-full text-xs font-bold border border-red-500/30">
                                                                <XCircle size={14} /> Missing
                                                        </div>
                                                    )}
                                                </td>
                                                <td className="py-4 text-right pr-2 text-sm text-gray-500">
                                                    {user.lastCheckInDate || 'Never'}
                                                </td>
                                            </tr>
                                        );
                                    })
                                )}
                            </tbody>
                        </table>
                    </div>
                )}
           </div>
        </div>
      )}

      {activeTab === 'settings' && (
        <div className="animate-fade-in space-y-6">

            {/* Cloud Config Section */}
            <div className="glass p-6 rounded-2xl border border-blue-500/20">
                <h3 className="text-xl font-bold mb-4 flex items-center gap-2 text-blue-400">
                    <Cloud /> Database Connection
                </h3>

                {/* Default Config Banner */}
                {hasDefaults && (
                    <div className="mb-6 p-4 bg-blue-900/20 border border-blue-400/30 rounded-xl flex items-center justify-between gap-3">
                        <div className="text-sm text-blue-200">
                            <strong>System Default Active:</strong> Using hardcoded connection keys.
                        </div>
                    </div>
                )}

                <p className="text-sm text-gray-400 mb-6">
                    Connect to JSONBin.io to allow users to sync data across different devices.
                </p>

                <div className="space-y-4">
                    <div>
                        <label className="text-xs font-bold text-gray-500 block mb-1">Bin ID</label>
                        <input 
                            type="text" 
                            value={cloudConfig.binId} 
                            onChange={(e) => setCloudConfig({...cloudConfig, binId: e.target.value})}
                            className="w-full bg-black/50 border border-white/10 rounded-lg p-3 text-white focus:border-blue-500 focus:outline-none font-mono"
                            placeholder="e.g. 65d4f..."
                        />
                    </div>
                    <div>
                        <label className="text-xs font-bold text-gray-500 block mb-1">Master Key (X-Master-Key)</label>
                        <input 
                            type="password" 
                            value={cloudConfig.apiKey} 
                            onChange={(e) => setCloudConfig({...cloudConfig, apiKey: e.target.value})}
                            className="w-full bg-black/50 border border-white/10 rounded-lg p-3 text-white focus:border-blue-500 focus:outline-none font-mono"
                            placeholder="e.g. $2a$10$..."
                        />
                    </div>

                    <div className="flex gap-4 pt-2">
                        <button 
                            onClick={handleSaveCloudConfig}
                            disabled={isVerifying}
                            className={`flex-1 py-3 rounded-xl font-bold text-white transition-colors flex items-center justify-center gap-2 ${isVerifying ? 'bg-blue-800' : 'bg-blue-600 hover:bg-blue-500'}`}
                        >
                            {isVerifying && <Loader2 className="animate-spin" size={18} />}
                            {cloudConfig.enabled ? 'Update Connection' : 'Connect Cloud'}
                        </button>

                        {cloudConfig.enabled && !isVerifying && (
                            <button 
                                onClick={handleDisconnectOrReset}
                                className={`px-6 py-3 rounded-xl font-bold transition-colors flex items-center gap-2 ${hasDefaults ? 'bg-yellow-600/50 text-yellow-200 hover:bg-yellow-600' : 'bg-red-900/50 text-red-300 hover:bg-red-900'}`}
                            >
                                {hasDefaults ? <RefreshCw size={18} /> : <CloudOff size={18} />}
                                {hasDefaults ? 'Reset to Default' : 'Disconnect'}
                            </button>
                        )}
                    </div>
                </div>
            </div>

            {/* Backup Section */}
            <div className="glass p-6 rounded-2xl border border-white/10">
                <h3 className="text-xl font-bold mb-4 flex items-center gap-2 text-white">
                    <Database /> Manual Backup
                </h3>
                <p className="text-sm text-gray-400 mb-6">
                    Download a local copy of the entire database (Users + Playlist) or restore from a file.
                </p>

                <div className="grid grid-cols-2 gap-4">
                    <button 
                        onClick={handleExportData}
                        className="py-4 bg-white/5 border border-white/10 hover:bg-white/10 rounded-xl flex flex-col items-center justify-center gap-2 transition-all"
                    >
                        <Download size={24} className="text-neon-green" /> 
                        <span className="font-bold">Backup to JSON</span>
                    </button>

                    <div className="relative">
                        <input type="file" ref={fileInputRef} onChange={handleFileChange} accept=".json" className="hidden" />
                        <button 
                            onClick={handleImportClick}
                            className="w-full h-full py-4 bg-white/5 border border-white/10 hover:bg-white/10 rounded-xl flex flex-col items-center justify-center gap-2 transition-all"
                        >
                            <Upload size={24} className="text-orange-400" /> 
                            <span className="font-bold">Restore from JSON</span>
                        </button>
                    </div>
                </div>
            </div>

            {settingsMsg && (
                <div className={`p-4 rounded-xl text-center font-medium border animate-pulse ${
                    settingsMsg.includes('SUCCESS') ? 'bg-green-900/20 border-green-500/30 text-green-300' : 
                    settingsMsg.includes('ERROR') ? 'bg-red-900/20 border-red-500/30 text-red-300' :
                    'bg-white/10 border-white/20 text-white'
                }`}>
                    {settingsMsg}
                </div>
            )}
        </div>
      )}
    </div>
  );
};

