                 {/* Step 2 */}
                 <div className="flex gap-4 relative z-10">
                     <div className="w-8 h-8 rounded-full bg-[#16133a] text-purple-400 flex items-center justify-center font-bold text-sm shrink-0 border border-purple-500 shadow-[0_0_10px_rgba(168,85,247,0.3)]">2</div>
                     <div>
                         <h4 className="font-bold text-purple-300 text-sm flex items-center gap-2">
                             <PlayCircle size={14} /> Listen on Spotify
                         </h4>
                         <p className="text-xs text-gray-400 mt-1 leading-relaxed">
                             Open the <strong>Daily Playlist</strong> link provided inside. Listen to the songs fully on Spotify.
                         </p>
                     </div>
                 </div>

                 {/* Step 3 */}
                 <div className="flex gap-4 relative z-10">
                     <div className="w-8 h-8 rounded-full bg-[#16133a] text-green-400 flex items-center justify-center font-bold text-sm shrink-0 border border-green-500 shadow-[0_0_10px_rgba(34,197,94,0.3)]">3</div>
                     <div>
